    try {
      const [qRes, jRes] = await Promise.all([
        fetch('/api/admin/queue'),
        fetch('/api/admin/jobs?limit=20'),
      ]);
      const qData = await qRes.json();
      const jData = await jRes.json();
      setEntries(qData.entries || []);
      setJobs(jData.jobs || []);
    } catch (err) {
      console.error('Failed to fetch queue data', err);
    } finally {
      setLoading(false);
    }
  }

  async function handlePublish(date: string, difficulty: string) {
    setActing(`publish-${date}-${difficulty}`);
    try {
      const res = await fetch('/api/admin/queue/publish', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ date, difficulty }),
      });
      const data = await res.json();
      if (!data.success) alert(data.error || 'Failed to publish');
      else fetchAll();
    } catch {
      alert('Request failed');
    } finally {
      setActing(null);
    }
  }

  async function handleReject() {
    if (!rejectId || !rejectReason.trim()) return;
    setActing(`reject-${rejectId}`);
    try {
      const res = await fetch('/api/admin/queue/reject', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ entryId: rejectId, reason: rejectReason }),
      });
      const data = await res.json();
      if (data.success) {
        setRejectId(null);
        setRejectReason('');
        fetchAll();
      }
    } catch {
      alert('Request failed');
    } finally {
      setActing(null);
    }
  }

  async function handleRegenerate(date: string, difficulty: string) {
    setRegenerating(true);
    try {
      const res = await fetch('/api/admin/queue/regenerate', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ date, difficulty }),
      });
      const data = await res.json();
      if (!data.success) alert(data.error || 'Regeneration failed');
      else fetchAll();
    } catch {
      alert('Request failed');
    } finally {
      setRegenerating(false);
    }
  }

  const statusVariant: Record<string, 'success' | 'secondary' | 'primary'> = {
    pending: 'primary',
    published: 'success',
    rejected: 'secondary',
    expired: 'secondary',
  };

  const jobStatusVariant: Record<string, 'success' | 'secondary' | 'primary'> = {
    queued: 'secondary',
    running: 'primary',
    completed: 'success',
    failed: 'secondary',
  };

  return (
    <div className="flex flex-col gap-10">
      <header className="flex flex-col gap-2 border-b border-border pb-8 sm:flex-row sm:items-end sm:justify-between">
        <div>
          <h1 className="text-2xl font-semibold tracking-tight text-text-1">Publish queue</h1>
          <p className="mt-1 max-w-xl text-sm leading-relaxed text-text-2">
            Pre-generated riddles waiting for their scheduled publish time. The daily cron
            promotes the top-priority pending entry at midnight IST.
          </p>
        </div>
        <Button variant="secondary" size="sm" onClick={fetchAll} disabled={loading}>
          <RefreshCw size={14} className={loading ? 'animate-spin' : ''} /> Refresh
        </Button>
      </header>

      {/* Queue Entries */}
      <section>
        <h2 className="text-sm font-semibold text-text-1 mb-4">Queue entries</h2>
        {loading ? (
          <div className="flex flex-col gap-3">
            {[1, 2, 3].map((i) => (
              <div key={i} className="skeleton-shimmer h-20 rounded-xl" />
            ))}
          </div>
        ) : entries.length === 0 ? (
          <Card padding="lg" className="text-center text-sm text-text-3">
            No queue entries. The generation cron creates entries automatically, or you can
            regenerate manually below.
          </Card>
        ) : (
          <div className="flex flex-col gap-3">
            {entries.map((entry) => (
              <Card key={entry.id} padding="md" className="flex flex-col gap-3">
                <div className="flex items-start justify-between">
                  <div className="flex flex-wrap items-center gap-2">
                    <span className="text-sm font-semibold text-text-1">{entry.target_date}</span>
                    <Badge variant="secondary" size="sm" className="font-mono uppercase">
                      {entry.difficulty}
                    </Badge>
                    <Badge variant={statusVariant[entry.status] || 'secondary'} size="sm">
                      {entry.status}
                    </Badge>
                    {entry.published_at && (
                      <span className="text-[11px] text-text-4">
                        Published {new Date(entry.published_at).toLocaleString()}
                      </span>
                    )}
                  </div>
                  {entry.status === 'pending' && (
                    <div className="flex gap-1 shrink-0">
                      <Button
                        size="sm"
                        onClick={() => handlePublish(entry.target_date, entry.difficulty)}
                        disabled={acting !== null}
                      >
                        Publish now
                      </Button>
                      <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => setRejectId(entry.id)}
                        disabled={acting !== null}
                      >
                        Reject
                      </Button>
                    </div>
                  )}
                </div>

                {entry.riddle && (
                  <div className="border-t border-border-subtle pt-3">
                    <p className="text-sm leading-relaxed text-text-2">{entry.riddle.question}</p>
                    <div className="mt-2 flex gap-4 text-xs text-text-3">
                      <span>Answer: <span className="font-mono text-text-2">{entry.riddle.answer}</span></span>
                    </div>
                  </div>
                )}

                {entry.rejected_reason && (
                  <p className="text-xs text-error">Rejected: {entry.rejected_reason}</p>
                )}

                {/* Inline reject form */}
                {rejectId === entry.id && (
                  <div className="flex items-end gap-2 border-t border-border pt-3">
                    <div className="flex-1">
                      <label className="text-[11px] text-text-3 mb-1 block">Rejection reason</label>
                      <input
                        type="text"
                        value={rejectReason}
                        onChange={(e) => setRejectReason(e.target.value)}
                        placeholder="Why is this being rejected?"
                        className="input"
                        autoFocus
                      />
                    </div>
                    <Button size="sm" onClick={handleReject} disabled={!rejectReason.trim()}>
                      Confirm
                    </Button>
                    <Button variant="ghost" size="sm" onClick={() => { setRejectId(null); setRejectReason(''); }}>
                      Cancel
                    </Button>
                  </div>
                )}
              </Card>
            ))}
          </div>
        )}
      </section>

      {/* Manual regeneration */}
      <section>
        <h2 className="text-sm font-semibold text-text-1 mb-2">Regenerate</h2>
        <p className="text-xs text-text-3 mb-4">
          Generate a new candidate for a specific date. This runs the full AI pipeline.
        </p>
        <RegenerateForm onRegenerate={handleRegenerate} disabled={regenerating} />
      </section>

      {/* Generation Jobs */}
      <section>
        <h2 className="text-sm font-semibold text-text-1 mb-4">Recent generation jobs</h2>
        {jobs.length === 0 ? (
          <Card padding="md" className="text-sm text-text-3">
            No generation jobs recorded yet.
          </Card>
        ) : (
          <Card padding="none" className="overflow-hidden">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b border-border text-left text-[11px] uppercase tracking-wide text-text-3">
                  <th className="px-5 py-3 font-medium">Date</th>
                  <th className="px-5 py-3 font-medium">Difficulty</th>
                  <th className="px-5 py-3 font-medium">Status</th>
                  <th className="px-5 py-3 font-medium">Duration</th>
                  <th className="px-5 py-3 font-medium">Retries</th>
                  <th className="px-5 py-3 font-medium">Error</th>
                  <th className="px-5 py-3 font-medium">Created</th>
                </tr>
              </thead>
              <tbody>
                {jobs.map((job) => (
                  <tr key={job.id} className="border-b border-border-subtle">
                    <td className="px-5 py-3 font-mono text-text-1">{job.target_date}</td>
                    <td className="px-5 py-3 text-text-2">{job.difficulty}</td>
                    <td className="px-5 py-3">
                      <Badge variant={jobStatusVariant[job.status] || 'secondary'} size="sm">
                        {job.status}
                      </Badge>
                    </td>
                    <td className="px-5 py-3 font-mono tabular-nums text-text-2">
                      {job.duration_ms ? `${job.duration_ms}ms` : '—'}
                    </td>
                    <td className="px-5 py-3 font-mono tabular-nums text-text-2">{job.retry_count}</td>
                    <td className="px-5 py-3 text-error text-xs max-w-[200px] truncate">
                      {job.error_message || '—'}
                    </td>
                    <td className="px-5 py-3 text-[11px] text-text-3">
                      {new Date(job.created_at).toLocaleString()}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </Card>
        )}
      </section>
    </div>
  );
}

function RegenerateForm({
  onRegenerate,
  disabled,
}: {
  onRegenerate: (date: string, difficulty: string) => void;
  disabled: boolean;
}) {
  const tomorrow = new Date();
  tomorrow.setDate(tomorrow.getDate() + 1);
  const [date, setDate] = useState(tomorrow.toISOString().split('T')[0]);
  const [difficulty, setDifficulty] = useState('medium');

  return (
    <div className="flex items-end gap-3">
      <div>
        <label className="text-[11px] text-text-3 mb-1 block">Target date</label>
        <input
          type="date"
          value={date}
          onChange={(e) => setDate(e.target.value)}
          className="input"
        />
      </div>
      <div>
        <label className="text-[11px] text-text-3 mb-1 block">Difficulty</label>
        <select value={difficulty} onChange={(e) => setDifficulty(e.target.value)} className="input">
          <option value="easy">Easy</option>
          <option value="medium">Medium</option>
          <option value="hard">Hard</option>
        </select>
      </div>
      <Button onClick={() => onRegenerate(date, difficulty)} disabled={disabled} size="sm">
        {disabled ? 'Generating…' : 'Generate'}
      </Button>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { Plus, Calendar, CheckCircle2, Clock, AlertCircle, Trash2, Edit3, Eye } from 'lucide-react';
import { Card } from '@/components/ui/Card';
import { Button } from '@/components/ui/Button';
import { Badge } from '@/components/ui/Badge';

type RiddleStatus = 'draft' | 'scheduled' | 'published' | 'archived';
type Difficulty = 'easy' | 'medium' | 'hard';

interface ScheduledRiddle {
  id: string;
  publish_date: string;
  difficulty: Difficulty;
  question: string;
  answer: string;
  explanation: string;
  status: RiddleStatus;
}

export default function ScheduledRiddlesPage() {
  const [riddles, setRiddles] = useState<ScheduledRiddle[]>([]);
  const [loading, setLoading] = useState(true);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);

  const [form, setForm] = useState({
    publish_date: new Date().toISOString().split('T')[0],
    difficulty: 'medium' as Difficulty,
    question: '',
    answer: '',
    explanation: '',
    status: 'scheduled' as RiddleStatus,
  });

  const [saving, setSaving] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    fetchRiddles();
  }, []);

  async function fetchRiddles() {
    try {
      const res = await fetch('/api/admin/riddles');
      const data = await res.json();
      if (data.success) setRiddles(data.riddles);
    } catch (err) {
      console.error('Failed to fetch riddles', err);
    } finally {
      setLoading(false);
    }
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setSaving(true);
    setError(null);

    const url = editingId ? `/api/admin/riddles/${editingId}` : '/api/admin/riddles';
    const method = editingId ? 'PATCH' : 'POST';

    try {
      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(form),
      });
      const data = await res.json();

      if (!data.success) {
        setError(data.error);
      } else {
        setIsFormOpen(false);
        setEditingId(null);
        setForm({
          publish_date: new Date().toISOString().split('T')[0],
          difficulty: 'medium',
          question: '',
          answer: '',
          explanation: '',
          status: 'scheduled',
        });
        fetchRiddles();
      }
    } catch {
      setError('An unexpected error occurred.');
    } finally {
      setSaving(false);
    }
  }

  async function handleDelete(id: string) {
    if (!confirm('Delete this scheduled riddle?')) return;
    try {
      const res = await fetch(`/api/admin/riddles/${id}`, { method: 'DELETE' });
      if (res.ok) fetchRiddles();
    } catch {
      alert('Failed to delete');
    }
  }

  function startEdit(riddle: ScheduledRiddle) {
    setEditingId(riddle.id);
    setForm({
      publish_date: riddle.publish_date,
      difficulty: riddle.difficulty,
      question: riddle.question,
      answer: riddle.answer,
      explanation: riddle.explanation,
      status: riddle.status,
    });
    setIsFormOpen(true);
  }

  const statusVariant: Record<RiddleStatus, 'secondary' | 'success' | 'primary'> = {
    draft: 'secondary',
    scheduled: 'primary',
    published: 'success',
    archived: 'secondary',
  };

  return (
    <div className="flex flex-col gap-10">
      {/* Header */}
      <header className="flex flex-col gap-2 border-b border-border pb-8 sm:flex-row sm:items-end sm:justify-between">
        <div>
          <h1 className="text-2xl font-semibold tracking-tight text-text-1">Scheduled riddles</h1>
          <p className="mt-1 max-w-xl text-sm leading-relaxed text-text-2">
            Pre-schedule riddles for specific dates. Scheduled riddles override AI-generated ones
            when their publish date arrives.
          </p>
        </div>
        <Button
          onClick={() => {
            setEditingId(null);
            setForm({
              publish_date: new Date().toISOString().split('T')[0],
              difficulty: 'medium',
              question: '',
              answer: '',
              explanation: '',
              status: 'scheduled',
            });
            setIsFormOpen(!isFormOpen);
          }}
          size="sm"
        >
          {isFormOpen ? 'Close' : (
            <span className="flex items-center gap-1.5">
              <Plus size={16} /> Schedule riddle
            </span>
          )}
        </Button>
      </header>

      {/* Form */}
      {isFormOpen && (
        <Card padding="lg" className="flex flex-col gap-6 lg:grid lg:grid-cols-[1.2fr_0.8fr] lg:gap-8">
          <form onSubmit={handleSubmit} className="flex flex-col gap-5">
            <div className="grid grid-cols-3 gap-4">
              <div>
                <label className="text-[11px] font-medium uppercase tracking-wide text-text-3 mb-2 block">
                  Publish date
                </label>
                <input
                  type="date"
                  value={form.publish_date}
                  onChange={(e) => setForm({ ...form, publish_date: e.target.value })}
                  className="input"
                  required
                />
              </div>
              <div>
                <label className="text-[11px] font-medium uppercase tracking-wide text-text-3 mb-2 block">
                  Difficulty
                </label>
                <select
                  value={form.difficulty}
                  onChange={(e) => setForm({ ...form, difficulty: e.target.value as Difficulty })}
                  className="input"
                >
                  <option value="easy">Easy</option>
                  <option value="medium">Medium</option>
                  <option value="hard">Hard</option>
                </select>
              </div>
              <div>
                <label className="text-[11px] font-medium uppercase tracking-wide text-text-3 mb-2 block">
                  Status
                </label>
                <select
                  value={form.status}
                  onChange={(e) => setForm({ ...form, status: e.target.value as RiddleStatus })}
                  className="input"
                >
                  <option value="draft">Draft</option>
                  <option value="scheduled">Scheduled</option>
                  <option value="published">Published</option>
                  <option value="archived">Archived</option>
                </select>
              </div>
            </div>

            <div>
              <label className="text-[11px] font-medium uppercase tracking-wide text-text-3 mb-2 block">
                Question
              </label>
              <textarea
                value={form.question}
                onChange={(e) => setForm({ ...form, question: e.target.value })}
                placeholder="The riddle question…"
                className="input min-h-[120px] resize-y"
                required
              />
            </div>

            <div className="grid grid-cols-[1fr_2fr] gap-4">
              <div>
                <label className="text-[11px] font-medium uppercase tracking-wide text-text-3 mb-2 block">
                  Answer
                </label>
                <input
                  type="text"
                  value={form.answer}
                  onChange={(e) => setForm({ ...form, answer: e.target.value })}
                  placeholder="Final answer"
                  className="input"
                  required
                />
              </div>
              <div>
                <label className="text-[11px] font-medium uppercase tracking-wide text-text-3 mb-2 block">
                  Explanation
                </label>
                <input
                  type="text"
                  value={form.explanation}
                  onChange={(e) => setForm({ ...form, explanation: e.target.value })}
                  placeholder="Step-by-step solution"
                  className="input"
                  required
                />
              </div>
            </div>

            {error && (
              <div className="flex items-center gap-2 text-sm text-error">
                <AlertCircle size={14} /> {error}
              </div>
            )}

            <Button type="submit" disabled={saving}>
              {saving ? 'Saving…' : editingId ? 'Update riddle' : 'Schedule riddle'}
            </Button>
          </form>

          {/* Preview */}
          <div className="border-l border-border pl-8 hidden lg:flex flex-col gap-4">
            <div className="flex items-center gap-2 text-text-3 text-xs font-medium">
              <Eye size={14} /> Preview
            </div>
            <Card padding="md" className="flex flex-col gap-4 bg-bg">
              <div className="flex gap-2">
                <Badge variant="secondary" size="sm" className="font-mono uppercase">
                  {form.difficulty}
                </Badge>
                <span className="text-[11px] text-text-4">{form.publish_date}</span>
              </div>
              <p className="text-[15px] leading-relaxed text-text-1">
                {form.question || <span className="text-text-4">Question will appear here…</span>}
              </p>
              {form.explanation && (
                <div className="border-t border-border pt-3">
                  <p className="text-[11px] font-medium text-text-3 mb-1">Explanation</p>
                  <p className="text-sm leading-relaxed text-text-2">{form.explanation}</p>
                </div>
              )}
            </Card>
          </div>
        </Card>
      )}

      {/* List */}
      <div className="flex flex-col gap-3">
        {loading ? (
          <div className="flex flex-col gap-3">
            {[1, 2, 3].map((i) => (
              <div key={i} className="skeleton-shimmer h-20 rounded-xl" />
            ))}
          </div>
        ) : riddles.length === 0 ? (
          <Card padding="lg" className="text-center text-sm text-text-3">
            No riddles scheduled. The AI pipeline generates riddles automatically when no
            scheduled override exists.
          </Card>
        ) : (
          riddles.map((riddle) => (
            <Card key={riddle.id} padding="md" className="flex items-center gap-5">
              <div className="flex h-11 w-11 shrink-0 items-center justify-center rounded-lg border border-border bg-bg-muted text-text-3">
                <Calendar size={18} />
              </div>

              <div className="min-w-0 flex-1">
                <div className="flex flex-wrap items-center gap-2 mb-1">
                  <span className="text-sm font-semibold text-text-1">{riddle.publish_date}</span>
                  <Badge variant="secondary" size="sm" className="font-mono uppercase">
                    {riddle.difficulty}
                  </Badge>
                  <Badge variant={statusVariant[riddle.status]} size="sm">
                    {riddle.status}
                  </Badge>
                </div>
                <p className="truncate text-sm text-text-3 max-w-md">{riddle.question}</p>
              </div>

              <div className="flex gap-1 shrink-0">
                <Button variant="ghost" size="sm" onClick={() => startEdit(riddle)}>
                  <Edit3 size={16} />
                </Button>
                <Button variant="ghost" size="sm" onClick={() => handleDelete(riddle.id)} className="text-error hover:text-error">
                  <Trash2 size={16} />
                </Button>
              </div>
            </Card>
          ))
        )}
      </div>
    </div>
  );
}

import { NextRequest, NextResponse } from 'next/server';
import { createClient } from '@/utils/supabase/server';
import { requireAdmin } from '@/lib/auth/requireAdmin';

/**
 * PATCH /api/admin/ai/config
 * 
 * Updates global AI engine settings.
 */
export async function PATCH(req: NextRequest) {
  try {
    const isAdmin = await requireAdmin();
    if (!isAdmin) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 403 });
    }

    const body = await req.json();
    const supabase = await createClient();

    console.log('[API/ADMIN/AI/CONFIG] Received update request:', body);

    const { error, data: updatedData } = await (supabase as any)
      .from('ai_settings')
      .upsert({ 
        key: 'engine_config',
        value: body,
        updated_at: new Date().toISOString()
      }, { onConflict: 'key' })
      .select('value')
      .single();

    if (error) {
      console.error('[ADMIN AI CONFIG ERROR]', error);
      return NextResponse.json({ error: error.message }, { status: 500 });
    }

    console.log(`[AI SETTINGS UPDATED] Success:`, updatedData?.value);
    if (body.safe_mode) console.log(`[AI SAFE MODE] Enabled`);

    return NextResponse.json({ success: true, config: updatedData?.value });

  } catch (err) {
    console.error('[ADMIN API ERROR]', err);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { createClient } from '@/utils/supabase/server';
import { requireAdmin } from '@/lib/auth/requireAdmin';

/**
 * GET /api/admin/ai/stats
 * 
 * Fetches aggregated AI pipeline telemetry for charts.
 */
export async function GET(req: NextRequest) {
  try {
    const isAdmin = await requireAdmin();
    if (!isAdmin) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 403 });
    }

    const supabase = await createClient();

    // Fetch aggregated daily stats from the view
    const { data: stats, error: statsError } = await supabase
      .from('v_pipeline_stats')
      .select('*')
      .limit(30)
      .order('day', { ascending: false });

    if (statsError) {
      console.error('[ADMIN AI STATS ERROR]', statsError);
      return NextResponse.json({ error: 'Failed to fetch telemetry' }, { status: 500 });
    }

    // Fetch current AI settings
    const { data: config, error: configError } = await supabase
      .from('ai_settings')
      .select('value')
      .eq('key', 'engine_config')
      .maybeSingle();

    const engineConfig = (config as any)?.value || { is_enabled: true, safe_mode: false, max_retries: 3, mode: 'standard' };

    return NextResponse.json({ stats, config: engineConfig });

  } catch (err) {
    console.error('[ADMIN API ERROR]', err);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { createClient } from '@/utils/supabase/server';
import { requireAdmin } from '@/lib/auth/requireAdmin';
import { z } from 'zod';

const updateSchema = z.object({
  status: z.enum(['pending', 'approved', 'rejected', 'rewarded']),
  adminNotes: z.string().optional(),
  compensationXP: z.number().int().min(0).optional(),
});

/**
 * PATCH /api/admin/challenges/[id]
 * 
 * Resolves a riddle challenge.
 */
export async function PATCH(
  req: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const isAdmin = await requireAdmin();
    if (!isAdmin) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 403 });
    }

    const { id: challengeId } = await params;
    const body = await req.json();
    const { status, adminNotes, compensationXP } = updateSchema.parse(body);

    const supabase = await createClient();
    const { data: { user: adminUser } } = await supabase.auth.getUser();

    // 1. Fetch challenge details
    const { data: challenge, error: fetchError } = await supabase
      .from('challenge_submissions')
      .select('*, user_id, riddle_id')
      .eq('id', challengeId)
      .single();

    if (fetchError || !challenge) {
      return NextResponse.json({ error: 'Challenge not found' }, { status: 404 });
    }

    // 2. Process Approval Logic
    if (status === 'approved' && (challenge as any).status !== 'approved') {
      // Mark riddle as invalid globally
      await (supabase as any)
        .from('riddles')
        .update({ is_invalid: true })
        .eq('id', (challenge as any).riddle_id);

      console.log(`[RIDDLE INVALIDATED] riddle: ${(challenge as any).riddle_id} due to challenge: ${challengeId}`);

      // Award compensation XP if provided
      if (compensationXP && compensationXP > 0 && (challenge as any).user_id) {
        const { awardXP } = await import('@/lib/gamification/xp');
        await awardXP({
          userId: (challenge as any).user_id,
          base: compensationXP,
          bonuses: [],
          riddleId: (challenge as any).riddle_id
        });
        console.log(`[REWARDED] user: ${(challenge as any).user_id}, xp: ${compensationXP}`);
      }

      console.log(`[CHALLENGE APPROVED] challenge: ${challengeId}`);
    }

    // 3. Update Challenge Record
    const { error: updateError } = await (supabase as any)
      .from('challenge_submissions')
      .update({
        status,
        admin_notes: adminNotes,
        reviewed_by: adminUser?.id,
      })
      .eq('id', challengeId);

    if (updateError) {
      console.error('[CHALLENGE UPDATE ERROR]', updateError);
      return NextResponse.json({ error: 'Failed to update challenge' }, { status: 500 });
    }

    return NextResponse.json({ success: true });

  } catch (err) {
    console.error('[CHALLENGE RESOLVE ERROR]', err);
    return NextResponse.json({ error: 'Invalid request' }, { status: 400 });
  }
}

