import { NextRequest, NextResponse } from 'next/server';
import { publishFromQueue, preGenerateForDate } from '@/lib/admin/publishPipeline';
import { getOfficialDailyDate } from '@/lib/timezone';

export const maxDuration = 300;

/**
 * Cron: Publish today's riddle at midnight IST.
 * Runs at 18:30 UTC = 00:00 IST.
 *
 * 1. Promotes the top-priority pending queue entry to live.
 * 2. If no queue entry exists, runs an emergency generation as fallback.
 * 3. Returns confirmation with publish details.
 */
export async function GET(req: NextRequest) {
  const authHeader = req.headers.get('authorization');
  if (process.env.VERCEL_CRON_SECRET && authHeader !== `Bearer ${process.env.VERCEL_CRON_SECRET}`) {
    return new NextResponse('Unauthorized', { status: 401 });
  }

  const today = getOfficialDailyDate();
  const difficulty = (process.env.DAILY_POST_DIFFICULTY || 'medium') as 'easy' | 'medium' | 'hard';

  console.log(`[cron/daily-publish] Publishing for ${today} (${difficulty})`);

  // Check if a live riddle already exists (idempotency)
  const { createServiceClient } = await import('@/utils/supabase/server');
  const supabase = (await createServiceClient()) as any;

  const { data: existing } = await supabase
    .from('riddles')
    .select('id')
    .eq('daily_date', today)
    .eq('difficulty', difficulty)
    .eq('is_daily', true)
    .eq('status', 'published')
    .maybeSingle();

  if (existing) {
    return NextResponse.json({
      success: true,
      message: `Riddle already live for ${today}. No action needed.`,
      riddleId: existing.id,
      skipped: true,
    });
  }

  // Try to publish from queue
  const publishResult = await publishFromQueue(today, difficulty);

  if (publishResult.success) {
    console.log(`[cron/daily-publish] Published ${publishResult.riddleId} for ${today}`);
    return NextResponse.json({
      success: true,
      message: `Published riddle for ${today}.`,
      riddleId: publishResult.riddleId,
      source: 'queue',
    });
  }

  // Fallback: emergency generation
  console.warn(`[cron/daily-publish] No queue entry. Running emergency generation for ${today}.`);
  const genResult = await preGenerateForDate(today, difficulty);

  if (!genResult.success) {
    console.error(`[cron/daily-publish] Emergency generation failed for ${today}:`, genResult.error);
    return NextResponse.json(
      { success: false, error: `Publish failed: ${genResult.error}` },
      { status: 500 }
    );
  }

  // Publish the freshly generated entry
  const retryPublish = await publishFromQueue(today, difficulty);

  if (retryPublish.success) {
    console.log(`[cron/daily-publish] Emergency publish succeeded: ${retryPublish.riddleId}`);
    return NextResponse.json({
      success: true,
      message: `Emergency generated and published riddle for ${today}.`,
      riddleId: retryPublish.riddleId,
      source: 'emergency_generation',
    });
  }

  return NextResponse.json(
    { success: false, error: 'All publish attempts failed.' },
    { status: 500 }
  );
}

import { NextRequest, NextResponse } from 'next/server';
import { preGenerateForDate } from '@/lib/admin/publishPipeline';
import { getOfficialDailyDate, addOfficialCalendarDays } from '@/lib/timezone';

export const maxDuration = 300;

/**
 * Cron: Pre-generate tomorrow's riddle.
 * Runs at 15:00 UTC (8:30 PM IST) — 3.5 hours before the midnight publish.
 * Idempotent: skips if a pending queue entry already exists for tomorrow.
 */
export async function GET(req: NextRequest) {
  const authHeader = req.headers.get('authorization');
  if (process.env.VERCEL_CRON_SECRET && authHeader !== `Bearer ${process.env.VERCEL_CRON_SECRET}`) {
    return new NextResponse('Unauthorized', { status: 401 });
  }

  const today = getOfficialDailyDate();
  const tomorrow = addOfficialCalendarDays(today, 1);
  const difficulty = (process.env.DAILY_POST_DIFFICULTY || 'medium') as 'easy' | 'medium' | 'hard';

  console.log(`[cron/generate-riddle] Generating for ${tomorrow} (${difficulty})`);

  // Check if queue already has a pending entry for tomorrow
  const { createServiceClient } = await import('@/utils/supabase/server');
  const supabase = (await createServiceClient()) as any;

  const { data: existing } = await supabase
    .from('daily_riddle_queue')
    .select('id')
    .eq('target_date', tomorrow)
    .eq('difficulty', difficulty)
    .eq('status', 'pending')
    .limit(1)
    .maybeSingle();

  if (existing) {
    return NextResponse.json({
      success: true,
      message: `Queue entry already exists for ${tomorrow}. Skipped generation.`,
      skipped: true,
    });
  }

  // Also check if a live riddle already exists for tomorrow
  const { data: liveRiddle } = await supabase
    .from('riddles')
    .select('id')
    .eq('daily_date', tomorrow)
    .eq('difficulty', difficulty)
    .eq('is_daily', true)
    .eq('status', 'published')
    .maybeSingle();

  if (liveRiddle) {
    return NextResponse.json({
      success: true,
      message: `Live riddle already exists for ${tomorrow}. Skipped generation.`,
      skipped: true,
    });
  }

  const result = await preGenerateForDate(tomorrow, difficulty);

  if (!result.success) {
    console.error(`[cron/generate-riddle] Failed for ${tomorrow}:`, result.error);
    return NextResponse.json(
      { success: false, error: result.error, job: result.job },
      { status: 500 }
    );
  }

  return NextResponse.json({
    success: true,
    message: `Generated and queued riddle for ${tomorrow}.`,
    job: result.job,
  });
}

import { NextResponse } from 'next/server';
import { createClient } from '@/utils/supabase/server';
import { traceSocialAction } from '@/lib/analytics/pipelineEvents';

/** GET /api/leaderboard?type=xp|streak|accuracy|hard&limit=50 */
export async function GET(req: Request) {
  const { searchParams } = new URL(req.url);
  const type = searchParams.get('type') || 'xp';
  const limit = Math.min(Number(searchParams.get('limit') || 50), 100);

  traceSocialAction('leaderboard_fetch', { type, limit });

  const supabase = await createClient();

  let query = supabase
    .from('user_stats')
    .select(`
      user_id,
      total_xp,
      current_streak,
      best_streak,
      riddles_solved,
      hard_solved,
      correct_attempts,
      total_attempts,
      profiles (
        username,
        full_name,
        avatar_url
      )
    `);

  // Sorting logic
  if (type === 'xp') {
    query = query.order('total_xp', { ascending: false });
  } else if (type === 'streak') {
    query = query.order('current_streak', { ascending: false });
  } else if (type === 'hard') {
    query = query.order('hard_solved', { ascending: false });
  } else if (type === 'accuracy') {
    // Note: Accuracy isn't a direct column, it's (correct/total).
    // For simple implementation, we'll fetch then sort in JS or use a computed column/view.
    // For now, let's sort by correct_attempts as a proxy or fetch extra and sort.
    query = query.order('correct_attempts', { ascending: false });
  }

  const { data, error } = await query.limit(limit);

  if (error) {
    console.error('[LEADERBOARD ERROR]', error);
    return NextResponse.json({ error: 'Failed to fetch leaderboard' }, { status: 500 });
  }

  // Post-process to calculate accuracy and filter out users without usernames if desired
  let results = data.map((row: any) => ({
    user_id: row.user_id,
    username: row.profiles?.username || row.profiles?.full_name?.split(' ')[0] || 'Anonymous',
    avatar_url: row.profiles?.avatar_url,
    total_xp: row.total_xp,
    current_streak: row.current_streak,
    best_streak: row.best_streak,
    riddles_solved: row.riddles_solved,
    hard_solved: row.hard_solved,
    accuracy: row.total_attempts > 0 ? (row.correct_attempts / row.total_attempts) : 0,
  }));

  if (type === 'accuracy') {
    results.sort((a, b) => b.accuracy - a.accuracy);
  }

  return NextResponse.json(results);
}

import { NextResponse } from 'next/server';
import { createClient } from '@/utils/supabase/server';
import { validateUsername, isUsernameUpdateAllowed } from '@/lib/username';

/** 
 * POST /api/profile/username — Claim or update a username.
 * Optimized for RLS safety and resilient profile synchronization.
 */
export async function POST(req: Request) {
  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();

  if (!user) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  const { username: rawUsername } = await req.json();
  const username = (rawUsername || '').toLowerCase().trim();

  console.log(`[USERNAME CLAIM] user: ${user.id}, attempt: "${username}"`);

  // 1. Validate format
  const validation = validateUsername(username);
  if (!validation.valid) {
    console.log(`[USERNAME INVALID] "${username}": ${validation.error}`);
    return NextResponse.json({ 
      status: 'INVALID_USERNAME',
      error: validation.error 
    }, { status: 400 });
  }
  console.log(`[USERNAME VALID] "${username}"`);

  // 2. Safely fetch profile
  let { data: profile, error: fetchError } = await supabase
    .from('profiles')
    .select('id, username, username_updated_at')
    .eq('id', user.id)
    .maybeSingle() as { data: any | null; error: any };

  if (fetchError) {
    console.error('[PROFILE FETCH FAILED]', fetchError);
    // If recursion occurs, it usually happens here or on insert
  }

  if (!profile) {
    console.log(`[PROFILE MISSING] for ${user.id}`);

    const { data: newProfile, error: insertError } = await (supabase
      .from('profiles') as any)
      .insert({
        id: user.id,
        email: user.email || '',
        full_name: user.user_metadata?.full_name,
        avatar_url: user.user_metadata?.avatar_url,
        streak_count: 0,
        xp: 0
      })
      .select('id, username, username_updated_at')
      .single();

    if (insertError) {
      console.error('[PROFILE INSERT FAILED]', insertError);
      return NextResponse.json({ 
        error: insertError.message || 'Failed to initialize profile.',
        details: insertError
      }, { status: 500 });
    }

    profile = newProfile;
    console.log(`[PROFILE INSERT OK] Auto-created for ${user.id}`);
    console.log(`[RLS POLICY OK] Insert succeeded`);
  } else {
    console.log(`[PROFILE FETCHED] for ${user.id}`);
  }

  // Double check profile exists for TS
  if (!profile) {
    return NextResponse.json({ error: 'Critical: Profile unavailable after initialization attempt.' }, { status: 500 });
  }

  // 3. Check cooldown
  if (profile.username) {
    const cooldown = isUsernameUpdateAllowed(profile.username_updated_at);
    if (!cooldown.allowed) {
      return NextResponse.json({ 
        status: 'RENAME_COOLDOWN',
        error: `Username changes are limited to once every 30 days. Please wait ${cooldown.daysRemaining} days.`,
      }, { status: 429 });
    }
  }

  // 4. Check uniqueness
  const { data: existing } = await supabase
    .from('profiles')
    .select('id')
    .eq('username', username)
    .maybeSingle() as { data: any | null };

  if (existing && existing.id !== user.id) {
    console.log(`[USERNAME TAKEN] "${username}"`);
    return NextResponse.json({ 
      status: 'USERNAME_TAKEN',
      error: 'This username is already claimed by another user.' 
    }, { status: 409 });
  }

  // 5. Update profile
  const { error: updateError } = await (supabase.from('profiles') as any)
    .update({ 
      username, 
      username_updated_at: new Date().toISOString() 
    })
    .eq('id', user.id);

  if (updateError) {
    console.error('[PROFILE UPDATE FAILED]', updateError);
    return NextResponse.json({ 
      error: 'Failed to update username.',
      details: updateError 
    }, { status: 500 });
  }

  console.log(`[PROFILE UPDATE OK] user: ${user.id}, new_username: "${username}"`);
  console.log(`[RLS POLICY OK] Update succeeded`);

  return NextResponse.json({ 
    status: 'PROFILE_UPDATED',
    success: true, 
    username 
  });
}

import { NextResponse } from 'next/server';
import { createClient } from '@/utils/supabase/server';
import { insertAttempt } from '@/lib/riddles/queries';

/**
 * POST /api/riddles/give-up
 *
 * User abandons the riddle. 
 * Status: 'gave_up'
 * XP: 0 (No award for quitting)
 * Streak: Not updated (will break if no solve by end of day)
 */
export async function POST(req: Request) {
  try {
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();

    const { riddleId } = await req.json();

    if (!riddleId) {
      return NextResponse.json({ error: 'Missing riddleId' }, { status: 400 });
    }

    console.log(`[GIVE UP] user: ${user?.id || 'anon'}, riddle: ${riddleId}`);

    // 1. Record the attempt as 'gave_up'
    await insertAttempt({
      userId: user?.id || null,
      riddleId,
      submittedAnswer: 'ABANDONED',
      isCorrect: false,
      status: 'gave_up'
    });

    // 2. Update user stats total_attempts even if it's a give up
    if (user) {
      const { createServiceClient } = await import('@/utils/supabase/server');
      const serviceSupabase = (await createServiceClient()) as any;

      const { data: stats } = await serviceSupabase
        .from('user_stats')
        .select('total_attempts')
        .eq('user_id', user.id)
        .single();

      await serviceSupabase
        .from('user_stats')
        .upsert({
          user_id: user.id,
          total_attempts: (stats?.total_attempts || 0) + 1,
        });
    }

    // 3. Fetch the solution to reveal to the user
    const { getRiddleById } = await import('@/lib/riddles/queries');
    const dbRiddle = await getRiddleById(riddleId);

    console.log(`[ABANDONED] riddle: ${riddleId}`);

    return NextResponse.json({
      success: true,
      xpAwarded: 0,
      newStreak: null,
      answer: dbRiddle?.answer,
      explanation: dbRiddle?.explanation
    });

  } catch (err: any) {
    console.error('[GIVE UP API ERROR]', err);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

