'use client';

import { useEffect, useState } from 'react';
import { formatCountdown, getOfficialTimezoneShort, getSecondsUntilOfficialMidnight } from '@/lib/timezone';

export default function CountdownTimer({ minimal }: { minimal?: boolean }) {
  const [mounted, setMounted] = useState(false);
  const [secs, setSecs] = useState(0);
  const tz = getOfficialTimezoneShort();

  useEffect(() => {
    setSecs(getSecondsUntilOfficialMidnight());
    setMounted(true);
    const id = setInterval(() => setSecs(getSecondsUntilOfficialMidnight()), 1000);
    return () => clearInterval(id);
  }, []);

  if (minimal) {
    return (
      <span
        className="font-mono text-sm font-semibold tracking-[0.08em] text-text-1"
        suppressHydrationWarning
      >
        {mounted ? formatCountdown(secs) : '--:--:--'}
      </span>
    );
  }

  return (
    <div className="flex flex-wrap items-center gap-2.5">
      <span className="label text-[10px] text-text-4">Next reset · {tz}</span>
      <span
        className="font-mono text-sm font-semibold tracking-[0.08em] text-text-1"
        suppressHydrationWarning
      >
        {mounted ? formatCountdown(secs) : '--:--:--'}
      </span>
    </div>
  );
}

'use client';

import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Button } from '@/components/ui/Button';
import { Badge } from '@/components/ui/Badge';
import { Lightbulb, ChevronDown, ChevronUp } from 'lucide-react';

interface Props {
  hint1: string;
  hint2: string;
  disabled?: boolean;
  /** Number of hints currently revealed (0–2). Used for server-side scoring. */
  onLevelChange?: (level: number) => void;
}

export default function HintLadder({ hint1, hint2, disabled, onLevelChange }: Props) {
  const [level, setLevel] = useState(0);

  const setLevelTracked = (next: number) => {
    setLevel(next);
    onLevelChange?.(next);
  };

  return (
    <div className="flex flex-col gap-4">
      {/* Hint Selection Controls */}
      <div className="flex gap-2">
        <Button
          variant={level === 1 ? 'secondary' : 'ghost'}
          size="sm"
          onClick={() => setLevelTracked(level === 1 ? 0 : 1)}
          disabled={disabled}
          className="gap-2"
        >
          <Lightbulb size={14} className={level >= 1 ? 'text-primary' : 'text-text-4'} />
          Hint 1
          {level === 1 ? <ChevronUp size={14} /> : <ChevronDown size={14} />}
        </Button>

        {hint2 && (
          <Button
            variant={level === 2 ? 'secondary' : 'ghost'}
            size="sm"
            onClick={() => setLevelTracked(level === 2 ? 0 : 2)}
            disabled={disabled || level < 1}
            className="gap-2"
          >
            <Lightbulb size={14} className={level === 2 ? 'text-primary' : 'text-text-4'} />
            Hint 2
            {level === 2 ? <ChevronUp size={14} /> : <ChevronDown size={14} />}
          </Button>
        )}
      </div>

      {/* Hint Content Display */}
      <AnimatePresence mode="wait">
        {level > 0 && (
          <motion.div
            key={level}
            initial={{ opacity: 0, y: 5 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -5 }}
            transition={{ duration: 0.2 }}
            className="flex flex-col gap-3 border border-white/[0.08] bg-black/30 p-4 shadow-inner shadow-black/40"
          >
            <div className="flex items-center gap-2">
              <Badge variant="warning" size="sm">Level {level} Hint</Badge>
              <div className="h-px flex-1 bg-border/50" />
            </div>
            <p className="text-sm text-text-2 leading-relaxed italic pr-4">
              "{level === 1 ? hint1 : hint2}"
            </p>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

'use client';

import { useMemo, useState } from 'react';
import type { DailySolvedEntry, Difficulty } from '@/types';

interface Props {
  solvedDates: DailySolvedEntry[];
  days?: number;
}

const DAY_LABELS = ['', 'M', '', 'W', '', 'F', ''];

function getDifficultyOpacity(diff: Difficulty): number {
  if (diff === 'easy') return 0.4;
  if (diff === 'medium') return 0.65;
  return 1;
}

function getDifficultyColor(diff: Difficulty): string {
  if (diff === 'easy') return 'var(--color-success)';
  if (diff === 'hard') return 'var(--color-error, #ef4444)';
  return 'var(--color-primary)';
}

/**
 * Activity calendar — GitHub-style contribution graph.
 * - 90-day window by default
 * - 7-column grid aligned to actual weekdays
 * - Subtle opacity-based heat mapping by difficulty
 * - Hover tooltip showing date, difficulty, streak
 */
export default function ProgressCalendar({ solvedDates, days = 90 }: Props) {
  const [hovered, setHovered] = useState<string | null>(null);

  const { grid, monthLabels } = useMemo(() => {
    const today = new Date();
    const start = new Date(today);
    start.setDate(start.getDate() - days + 1);

    // Align start to the previous Sunday
    const startDow = start.getDay(); // 0=Sun
    start.setDate(start.getDate() - startDow);

    // Build solvedMap for O(1) lookups
    const solvedMap = new Map<string, DailySolvedEntry>();
    for (const entry of solvedDates) {
      solvedMap.set(entry.date, entry);
    }

    // Generate day cells grouped into weeks (columns)
    const weeks: Array<Array<{
      date: string;
      dow: number;
      isToday: boolean;
      entry: DailySolvedEntry | null;
      inRange: boolean;
    }>> = [];

    const todayStr = today.toISOString().split('T')[0];
    const rangeStart = new Date(today);
    rangeStart.setDate(rangeStart.getDate() - days + 1);
    const rangeStartStr = rangeStart.toISOString().split('T')[0];

    let cursor = new Date(start);
    let currentWeek: typeof weeks[0] = [];
    const mLabels: Array<{ label: string; weekIndex: number }> = [];
    let lastMonth = -1;

    while (cursor <= today || currentWeek.length > 0) {
      const dateStr = cursor.toISOString().split('T')[0];
      const dow = cursor.getDay();

      if (dow === 0 && currentWeek.length > 0) {
        weeks.push(currentWeek);
        currentWeek = [];
      }

      // Track month labels (show on first day of a new month)
      const month = cursor.getMonth();
      if (month !== lastMonth) {
        mLabels.push({
          label: cursor.toLocaleDateString('en-US', { month: 'short' }),
          weekIndex: weeks.length,
        });
        lastMonth = month;
      }

      currentWeek.push({
        date: dateStr,
        dow,
        isToday: dateStr === todayStr,
        entry: solvedMap.get(dateStr) ?? null,
        inRange: dateStr >= rangeStartStr && dateStr <= todayStr,
      });

      if (cursor > today && dow === 6) break;
      cursor.setDate(cursor.getDate() + 1);
    }

    if (currentWeek.length > 0) weeks.push(currentWeek);

    return { grid: weeks, monthLabels: mLabels };
  }, [solvedDates, days]);

  // Find hovered entry details
  const hoveredEntry = hovered ? solvedDates.find((e) => e.date === hovered) : null;

  return (
    <div className="flex flex-col gap-2">
      {/* Month labels */}
      <div className="flex gap-0 ml-[26px]">
        {monthLabels.map((ml, i) => (
          <div
            key={`${ml.label}-${i}`}
            className="text-[10px] font-medium text-text-4"
            style={{
              position: 'relative',
              left: `${ml.weekIndex * 14}px`,
              marginRight: i < monthLabels.length - 1 ? `${(monthLabels[i + 1]?.weekIndex - ml.weekIndex) * 14 - 30}px` : 0,
            }}
          >
            {ml.label}
          </div>
        ))}
      </div>

      <div className="flex gap-0.5">
        {/* Day-of-week labels */}
        <div className="flex flex-col gap-0.5 mr-1.5 pt-0">
          {DAY_LABELS.map((label, i) => (
            <div key={i} className="flex h-[12px] w-[14px] items-center justify-end text-[9px] text-text-4">
              {label}
            </div>
          ))}
        </div>

        {/* Grid */}
        <div className="flex gap-0.5">
          {grid.map((week, wi) => (
            <div key={wi} className="flex flex-col gap-0.5">
              {week.map((cell) => {
                const isSolved = cell.entry !== null;
                const difficulty = cell.entry?.difficulty ?? 'medium';

                return (
                  <div
                    key={cell.date}
                    className="relative cursor-default"
                    onMouseEnter={() => setHovered(cell.date)}
                    onMouseLeave={() => setHovered(null)}
                  >
                    <div
                      className={`h-[12px] w-[12px] rounded-[2px] transition-colors ${
                        !cell.inRange
                          ? 'bg-transparent'
                          : cell.isToday && !isSolved
                          ? 'ring-1 ring-text-3/40 bg-surface'
                          : isSolved
                          ? ''
                          : 'bg-surface-hover'
                      }`}
                      style={
                        isSolved && cell.inRange
                          ? {
                              backgroundColor: getDifficultyColor(difficulty),
                              opacity: getDifficultyOpacity(difficulty),
                            }
                          : undefined
                      }
                    />

                    {/* Tooltip */}
                    {hovered === cell.date && cell.inRange && (
                      <div className="absolute bottom-full left-1/2 z-50 mb-2 -translate-x-1/2 whitespace-nowrap rounded-lg border border-border bg-bg px-3 py-1.5 text-[11px] shadow-lg">
                        <span className="font-medium text-text-1">
                          {new Date(cell.date + 'T00:00:00').toLocaleDateString('en-US', {
                            weekday: 'short',
                            month: 'short',
                            day: 'numeric',
                          })}
                        </span>
                        {isSolved ? (
                          <span className="ml-2 text-text-2">
                            Solved ({difficulty})
                          </span>
                        ) : (
                          <span className="ml-2 text-text-4">No solve</span>
                        )}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          ))}
        </div>
      </div>

      {/* Legend */}
      <div className="mt-1 flex items-center gap-3 text-[10px] text-text-4">
        <span>Less</span>
        <div className="flex gap-0.5">
          <div className="h-[10px] w-[10px] rounded-[2px] bg-surface-hover" />
          <div className="h-[10px] w-[10px] rounded-[2px] bg-success/40" />
          <div className="h-[10px] w-[10px] rounded-[2px] bg-primary/65" />
          <div className="h-[10px] w-[10px] rounded-[2px] bg-error" />
        </div>
        <span>More</span>
      </div>
    </div>
  );
}

'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import Link from 'next/link';
import StreakChip from '@/components/StreakChip';
import { createClient } from '@/utils/supabase/client';
import UsernameModal from '@/components/profile/UsernameModal';
import type { Database } from '@/types/supabase';
import type { User } from '@supabase/supabase-js';
import { useChallengeSession } from '@/components/providers/ChallengeSessionProvider';
import { Topbar, Container } from '@/components/ui/Layout';
import { Button } from '@/components/ui/Button';

type Profile = Database['public']['Tables']['profiles']['Row'];

export interface HeaderProps {
  user: User | null;
  profile: Profile | null;
}

export default function Header({ user, profile }: HeaderProps) {
  const router = useRouter();
  const { session } = useChallengeSession();
  const [isSigningIn, setIsSigningIn] = useState(false);
  const [showUsernameModal, setShowUsernameModal] = useState(!!user && !profile?.username);

  const displayStreak = session?.streak?.currentStreak ?? profile?.streak_count ?? 0;

  async function handleSignIn() {
    setIsSigningIn(true);
    const supabase = createClient();
    const { error } = await supabase.auth.signInWithOAuth({
      provider: 'google',
      options: {
        redirectTo: `${window.location.origin}/auth/callback`,
        queryParams: { prompt: 'select_account' },
      },
    });
    if (error) {
      console.error('[OAUTH ERROR]', error.message);
      setIsSigningIn(false);
    }
  }

  async function handleSignOut() {
    const supabase = createClient();
    await supabase.auth.signOut();
    router.refresh();
  }

  return (
    <>
      <Topbar>
        <Container className="flex items-center justify-between w-full">
          {/* Brand & Nav */}
          <div className="flex items-center gap-10">
            <div
              className="flex items-center gap-2 cursor-pointer group"
              onClick={() => router.push('/')}
            >
              <div className="w-8 h-8 rounded-lg bg-primary flex items-center justify-center text-white font-black text-lg transition-transform group-hover:scale-105">
                ∑
              </div>
              <span className="font-display text-lg tracking-tight text-text-1">
                AdvaitAI
              </span>
            </div>

            <nav className="hidden md:flex items-center gap-6">
              <Link 
                href="/leaderboard" 
                className="text-sm font-medium text-text-2 hover:text-text-1 transition-colors"
              >
                Leaderboard
              </Link>
            </nav>
          </div>

          {/* User Actions */}
          <div className="flex items-center gap-6">
            {displayStreak > 0 && <StreakChip current={displayStreak} />}

            {user ? (
              <div className="flex items-center gap-4">
                <div 
                  className="flex items-center gap-2 cursor-pointer group"
                  onClick={() => profile?.username && router.push(`/u/${profile.username}`)}
                >
                  {profile?.avatar_url ? (
                    <img
                      src={profile.avatar_url}
                      alt="Avatar"
                      className="w-7 h-7 rounded-full border border-border group-hover:border-text-3 transition-colors"
                    />
                  ) : (
                    <div className="w-7 h-7 rounded-full bg-bg-subtle border border-border" />
                  )}
                  <span className="text-sm font-medium text-text-2 group-hover:text-text-1 transition-colors">
                    {profile?.username || profile?.full_name?.split(' ')[0] || 'User'}
                  </span>
                </div>
                <Button 
                  variant="ghost" 
                  size="sm" 
                  onClick={handleSignOut}
                >
                  Sign out
                </Button>
              </div>
            ) : (
              <Button 
                onClick={handleSignIn} 
                disabled={isSigningIn}
                size="sm"
              >
                {isSigningIn ? 'Redirecting…' : 'Sign in'}
              </Button>
            )}
          </div>
        </Container>
      </Topbar>

      <UsernameModal 
        isOpen={showUsernameModal} 
        onSuccess={() => {
          setShowUsernameModal(false);
          router.refresh();
        }}
      />
    </>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useRouter } from 'next/navigation';

type LeaderboardType = 'xp' | 'streak' | 'accuracy' | 'hard';

interface LeaderboardUser {
  user_id: string;
  username: string;
  avatar_url: string | null;
  total_xp: number;
  current_streak: number;
  best_streak: number;
  riddles_solved: number;
  hard_solved: number;
  accuracy: number;
}

export default function LeaderboardContent() {
  const router = useRouter();
  const [type, setType] = useState<LeaderboardType>('xp');
  const [users, setUsers] = useState<LeaderboardUser[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function fetchLeaderboard() {
      setLoading(true);
      try {
        const res = await fetch(`/api/leaderboard?type=${type}`);
        if (res.ok) {
          const data = await res.json();
          setUsers(data);
        }
      } catch (err) {
        console.error('Failed to fetch leaderboard:', err);
      } finally {
        setLoading(false);
      }
    }
    fetchLeaderboard();
  }, [type]);

  const tabs: { id: LeaderboardType; label: string }[] = [
    { id: 'xp', label: 'All-Time XP' },
    { id: 'streak', label: 'Streak' },
    { id: 'hard', label: 'Hard Solves' },
    { id: 'accuracy', label: 'Accuracy' },
  ];

  return (
    <div style={{ minHeight: '100vh', padding: '0 24px', display: 'flex', flexDirection: 'column', alignItems: 'center' }}>

      <main style={{ width: '100%', maxWidth: 860, padding: 'clamp(48px, 8vh, 96px) 0 80px', display: 'flex', flexDirection: 'column', gap: 48 }}>

        {/* Header */}
        <div style={{ textAlign: 'center' }}>
          <h1 className="font-display" style={{ fontSize: 'clamp(32px, 5vw, 52px)', fontWeight: 800, marginBottom: 12 }}>
            Global Rankings
          </h1>
          <p style={{ fontSize: 16, color: 'var(--text-3)' }}>
            The elite minds of the AdvaitAI community.
          </p>
        </div>

        {/* Tabs */}
        <div style={{ 
          display: 'flex', justifyContent: 'center', gap: 8, 
          padding: 6, background: 'var(--surface)', border: '1px solid var(--border)',
          borderRadius: 14, width: 'fit-content', margin: '0 auto'
        }}>
          {tabs.map((tab) => (
            <button
              key={tab.id}
              onClick={() => setType(tab.id)}
              style={{
                padding: '10px 18px', borderRadius: 10, fontSize: 14, fontWeight: 600,
                background: type === tab.id ? 'var(--text-1)' : 'transparent',
                color: type === tab.id ? 'var(--bg)' : 'var(--text-3)',
                transition: 'all 0.2s cubic-bezier(0.16, 1, 0.3, 1)',
                border: 'none', cursor: 'pointer'
              }}
            >
              {tab.label}
            </button>
          ))}
        </div>

        {/* List */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
          <AnimatePresence mode="wait">
            {loading ? (
              <motion.div
                key="loading"
                initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
                style={{ textAlign: 'center', padding: '40px 0', color: 'var(--text-4)' }}
              >
                Calculating rankings...
              </motion.div>
            ) : (
              <motion.div
                key="list"
                initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }}
                style={{ display: 'flex', flexDirection: 'column', gap: 12 }}
              >
                {users.length > 0 ? (
                  users.map((user, idx) => (
                    <RankRow 
                      key={user.user_id} 
                      user={user} 
                      rank={idx + 1} 
                      type={type} 
                      onClick={() => router.push(`/u/${user.username}`)}
                    />
                  ))
                ) : (
                  <div style={{ textAlign: 'center', padding: '40px 0', color: 'var(--text-4)' }}>
                    No data available yet.
                  </div>
                )}
              </motion.div>
            )}
          </AnimatePresence>
        </div>

      </main>
    </div>
  );
}

function RankRow({ user, rank, type, onClick }: { user: LeaderboardUser; rank: number; type: LeaderboardType; onClick: () => void }) {
  const getValue = () => {
    switch (type) {
      case 'xp': return `${user.total_xp} XP`;
      case 'streak': return `${user.current_streak} days`;
      case 'hard': return `${user.hard_solved} hard`;
      case 'accuracy': return `${Math.round(user.accuracy * 100)}%`;
    }
  };

  return (
    <motion.div
      onClick={onClick}
      whileHover={{ y: -2, background: 'var(--surface-hover)' }}
      style={{
        display: 'flex', alignItems: 'center', gap: 20,
        padding: '16px 24px', background: 'var(--surface)',
        border: '1px solid var(--border)', borderRadius: 14,
        cursor: 'pointer', transition: 'background 0.2s ease'
      }}
    >
      <span style={{ 
        fontSize: 15, fontWeight: 700, width: 24, 
        color: rank <= 3 ? 'var(--text-1)' : 'var(--text-4)' 
      }}>
        {rank}
      </span>

      <div style={{ display: 'flex', alignItems: 'center', gap: 14, flex: 1 }}>
        <div style={{
          width: 36, height: 36, borderRadius: '50%',
          background: 'var(--border-subtle)', overflow: 'hidden',
          display: 'flex', alignItems: 'center', justifyContent: 'center'
        }}>
          {user.avatar_url ? (
            <img src={user.avatar_url} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
          ) : (
            <span style={{ fontSize: 18 }}>👤</span>
          )}
        </div>
        <span style={{ fontSize: 16, fontWeight: 600, color: 'var(--text-1)' }}>
          {user.username}
        </span>
      </div>

      <span className="mono" style={{ fontSize: 15, fontWeight: 700, color: 'var(--text-2)' }}>
        {getValue()}
      </span>
    </motion.div>
  );
}

'use client';

import ProgressCalendar from '@/components/ProgressCalendar';
import type { UserStats, Achievement } from '@/types/gamification';
import type { DbProfile } from '@/types/supabase';
import type { DailySolvedEntry } from '@/types';
import { Container } from '@/components/ui/Layout';
import { Card } from '@/components/ui/Card';
import { Badge } from '@/components/ui/Badge';
import { Calendar, Award, Target, Flame } from 'lucide-react';
import Link from 'next/link';

interface SolveHistoryEntry {
  id: string;
  solvedAt: string;
  question: string;
  difficulty: string;
  dailyDate: string | null;
  slug: string | null;
}

interface Props {
  profile: DbProfile;
  stats: UserStats | null;
  activity: DailySolvedEntry[];
  achievements: (Achievement & { unlocked_at: string })[];
  xpRank: number | null;
  solveHistory: SolveHistoryEntry[];
}

export default function ProfileContent({ profile, stats, activity, achievements, xpRank, solveHistory }: Props) {
  const currentStreak = stats?.current_streak ?? 0;
  const bestStreak = stats?.best_streak ?? 0;
  const totalXP = stats?.total_xp ?? 0;
  const riddlesSolved = stats?.riddles_solved ?? 0;
  const easySolved = stats?.easy_solved ?? 0;
  const mediumSolved = stats?.medium_solved ?? 0;
  const hardSolved = stats?.hard_solved ?? 0;
  const accuracy =
    stats && stats.total_attempts > 0 ? Math.round((stats.correct_attempts / stats.total_attempts) * 100) : 0;

  const totalDiffSolved = easySolved + mediumSolved + hardSolved;

  return (
    <Container wide className="py-14 lg:py-20">
      <main className="mx-auto flex max-w-3xl flex-col gap-10">
        {/* Header */}
        <Card padding="lg" className="flex flex-col gap-6 sm:flex-row sm:items-center">
          <div className="h-20 w-20 shrink-0 overflow-hidden rounded-full border border-border bg-bg-muted">
            {profile.avatar_url ? (
              <img src={profile.avatar_url} alt="" className="h-full w-full object-cover" />
            ) : (
              <div className="flex h-full w-full items-center justify-center text-2xl font-semibold text-text-3">
                {(profile.username?.[0] || 'U').toUpperCase()}
              </div>
            )}
          </div>

          <div className="min-w-0 flex-1">
            <h1 className="text-2xl font-semibold tracking-tight text-text-1 sm:text-[1.75rem]">
              {profile.full_name || `@${profile.username}`}
            </h1>
            <div className="mt-2 flex flex-wrap items-center gap-x-3 gap-y-1 text-sm text-text-2">
              <span>@{profile.username}</span>
              <span className="text-text-4">·</span>
              <span className="inline-flex items-center gap-1.5">
                <Calendar size={14} className="text-text-3" />
                Joined{' '}
                {new Date(profile.created_at).toLocaleDateString('en-US', { month: 'short', year: 'numeric' })}
              </span>
            </div>
          </div>

          {xpRank != null && (
            <div className="sm:text-right">
              <p className="text-[11px] font-medium text-text-3">XP rank</p>
              <p className="font-mono text-2xl font-semibold tabular-nums text-text-1">#{xpRank}</p>
            </div>
          )}
        </Card>

        {/* Stats */}
        <div className="grid grid-cols-2 gap-3 sm:grid-cols-4">
          <StatCard icon={<Flame className="text-primary" size={16} />} label="Streak" value={currentStreak} sub={`best ${bestStreak}`} />
          <StatCard icon={<Award className="text-text-3" size={16} />} label="XP" value={totalXP.toLocaleString()} />
          <StatCard icon={<Target className="text-success" size={16} />} label="Solved" value={riddlesSolved} />
          <StatCard icon={<Calendar className="text-text-3" size={16} />} label="Accuracy" value={`${accuracy}%`} />
        </div>

        {/* Difficulty Breakdown */}
        {totalDiffSolved > 0 && (
          <section>
            <h2 className="text-sm font-semibold text-text-1">Difficulty breakdown</h2>
            <p className="mt-1 text-xs text-text-3">{totalDiffSolved} total solves by difficulty level.</p>
            <Card padding="md" className="mt-4">
              <div className="flex flex-col gap-3">
                <DiffBar label="Easy" count={easySolved} total={totalDiffSolved} color="bg-success" />
                <DiffBar label="Medium" count={mediumSolved} total={totalDiffSolved} color="bg-primary" />
                <DiffBar label="Hard" count={hardSolved} total={totalDiffSolved} color="bg-error" />
              </div>
            </Card>
          </section>
        )}

        {/* Activity Calendar */}
        <section>
          <h2 className="text-sm font-semibold text-text-1">Activity (90 days)</h2>
          <p className="mt-1 text-xs text-text-3">One cell per day · color encodes hardest difficulty solved.</p>
          <Card padding="md" className="mt-4">
            <ProgressCalendar solvedDates={activity} />
          </Card>
        </section>

        {/* Recent Solve History */}
        <section>
          <h2 className="text-sm font-semibold text-text-1">Recent solves</h2>
          <div className="mt-4 flex flex-col gap-2">
            {solveHistory.length > 0 ? (
              solveHistory.map((solve) => (
                <Card key={solve.id} padding="sm" className="flex items-center gap-3 px-4 py-3">
                  <Badge
                    variant={solve.difficulty === 'hard' ? 'danger' : solve.difficulty === 'easy' ? 'success' : 'warning'}
                    size="sm"
                    className="font-mono uppercase shrink-0"
                  >
                    {solve.difficulty}
                  </Badge>
                  <p className="min-w-0 flex-1 truncate text-sm text-text-2">
                    {solve.question}
                  </p>
                  <span className="shrink-0 text-[11px] text-text-4 font-mono">
                    {new Date(solve.solvedAt).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
                  </span>
                </Card>
              ))
            ) : (
              <Card padding="lg" className="text-center text-sm text-text-3">
                No solves recorded yet.
              </Card>
            )}
          </div>
        </section>

        {/* Achievements */}
        <section>
          <h2 className="text-sm font-semibold text-text-1">Achievements</h2>
          <div className="mt-4 grid gap-3 sm:grid-cols-2">
            {achievements.length > 0 ? (
              achievements.map((ach) => (
                <Card key={ach.id} padding="md" className="flex items-start gap-3">
                  <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-lg border border-border bg-bg-muted text-lg">
                    {ach.icon}
                  </div>
                  <div className="min-w-0">
                    <p className="text-sm font-medium text-text-1">{ach.name}</p>
                    <p className="mt-1 text-xs leading-relaxed text-text-3">{ach.description}</p>
                  </div>
                </Card>
              ))
            ) : (
              <Card padding="lg" className="col-span-full text-center text-sm text-text-3">
                No achievements yet.
              </Card>
            )}
          </div>
        </section>
      </main>
    </Container>
  );
}

function StatCard({
  icon,
  label,
  value,
  sub,
}: {
  icon: React.ReactNode;
  label: string;
  value: string | number;
  sub?: string;
}) {
  return (
    <Card padding="md" className="flex flex-col gap-2">
      <div className="flex items-center justify-between">
        <span className="text-[11px] font-medium text-text-3">{label}</span>
        {icon}
      </div>
      <div className="flex items-baseline gap-2">
        <span className="text-xl font-semibold tabular-nums text-text-1">{value}</span>
        {sub && <span className="text-[10px] text-text-4">{sub}</span>}
      </div>
    </Card>
  );
}

function DiffBar({
  label,
  count,
  total,
  color,
}: {
  label: string;
  count: number;
  total: number;
  color: string;
}) {
  const pct = total > 0 ? Math.round((count / total) * 100) : 0;
  return (
    <div className="flex items-center gap-3">
      <span className="w-16 text-xs font-medium text-text-2">{label}</span>
      <div className="flex-1 h-2 rounded-full bg-surface overflow-hidden">
