'use client';
import React, { useState, useEffect, useRef } from 'react';
import { Riddle } from '@/types';

const MAX_PER_DAY = 10;
const COOLDOWN_MS = 5000;
const REQUEST_TIMEOUT_MS = 45_000; // 45s — Groq can be slow under load

function getTodayKey() {
  return `advaitai_usage_${new Date().toISOString().split('T')[0]}`;
}

// ── Typed error states ────────────────────────────────────────────────
type GenerationErrorCode =
  | 'GENERATION_FAILED'
  | 'QUOTA_EXCEEDED'
  | 'GENERATION_TIMEOUT'
  | 'INVALID_RESPONSE'
  | 'GENERATION_ERROR'
  | 'NETWORK_ERROR';

const ERROR_MESSAGES: Record<GenerationErrorCode, string> = {
  GENERATION_FAILED: "Couldn't generate a unique riddle. Our AI tried 3× — try again in a moment.",
  QUOTA_EXCEEDED: 'Daily limit reached. Come back tomorrow for more challenges.',
  GENERATION_TIMEOUT: 'Request timed out. Groq may be under load — please try again.',
  INVALID_RESPONSE: 'Invalid request. Please try again.',
  GENERATION_ERROR: 'AI service temporarily unavailable. Please try again in a few minutes.',
  NETWORK_ERROR: 'Network error. Please check your connection and try again.',
};

interface GenerateMoreProps {
  sessionId: string;
  difficulty: string;
  onNewRiddle: (riddle: Partial<Riddle>) => void;
}

/**
 * GenerateMore — deterministic quota + state flow.
 *
 * Error handling contract:
 * - All errors typed via GenerationErrorCode
 * - Request has a hard 45s AbortController timeout
 * - Loading lock (requestInFlight ref) prevents spam
 * - Quota incremented ONLY when server returns generationCount
 * - DEV TRACE badge gated behind process.env.NODE_ENV === 'development'
 */
import { Button } from '@/components/ui/Button';
import { Badge } from '@/components/ui/Badge';
import { RotateCw, AlertTriangle, Lock, Info } from 'lucide-react';

export default function GenerateMore({ sessionId, difficulty, onNewRiddle }: GenerateMoreProps) {
  const [used, setUsed] = useState(0);
  const [loading, setLoading] = useState(false);
  const [cooldown, setCooldown] = useState(false);
  const [errorCode, setErrorCode] = useState<GenerationErrorCode | null>(null);
  const [attempts, setAttempts] = useState<any[]>([]);
  const [templateFamily, setTemplateFamily] = useState<string | null>(null);

  const requestInFlight = useRef(false);
  const cooldownTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const abortRef = useRef<AbortController | null>(null);

  useEffect(() => {
    setUsed(Number(localStorage.getItem(getTodayKey()) || 0));
    return () => {
      if (cooldownTimer.current) clearTimeout(cooldownTimer.current);
      abortRef.current?.abort();
    };
  }, []);

  const limitReached = used >= MAX_PER_DAY;
  const blocked = loading || cooldown || limitReached;
  const errorMsg = errorCode ? ERROR_MESSAGES[errorCode] : null;

  const handleGenerate = async () => {
    if (requestInFlight.current || blocked) return;
    requestInFlight.current = true;

    setLoading(true);
    setErrorCode(null);
    setAttempts([]);

    const controller = new AbortController();
    abortRef.current = controller;
    const timeoutId = setTimeout(() => controller.abort(), REQUEST_TIMEOUT_MS);

    try {
      const res = await fetch('/api/riddles/generate', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ difficulty, sessionId }),
        signal: controller.signal,
      });

      clearTimeout(timeoutId);
      const data = await res.json();

      if (!res.ok || !data.success) {
        if (data.attempts) setAttempts(data.attempts);
        throw new Error(data.code || 'GENERATION_ERROR');
      }

      if (typeof data.generationCount === 'number') {
        setUsed(data.generationCount);
        localStorage.setItem(getTodayKey(), String(data.generationCount));
      }

      if (data.riddle) {
        setCooldown(true);
        if (data.templateFamily) setTemplateFamily(data.templateFamily);
        cooldownTimer.current = setTimeout(() => setCooldown(false), COOLDOWN_MS);
        onNewRiddle(data.riddle);
      } else {
        throw new Error('INVALID_RESPONSE');
      }

    } catch (err) {
      clearTimeout(timeoutId);
      if (err instanceof Error) {
        if (err.name === 'AbortError') {
          setErrorCode('GENERATION_TIMEOUT');
        } else if (err.message in ERROR_MESSAGES) {
          setErrorCode(err.message as GenerationErrorCode);
        } else {
          setErrorCode('NETWORK_ERROR');
        }
      } else {
        setErrorCode('NETWORK_ERROR');
      }
    } finally {
      setLoading(false);
      requestInFlight.current = false;
      abortRef.current = null;
    }
  };

  return (
    <div className="flex flex-col gap-4">
      {/* ── Generate button ── */}
      <Button
        onClick={handleGenerate}
        disabled={blocked}
        variant="primary"
        size="lg"
        className="w-full shadow-lg shadow-primary/10 gap-2"
      >
        {loading ? (
          <>
            <RotateCw size={18} className="animate-spin" />
            Generating...
          </>
        ) : cooldown ? (
          'Please wait...'
        ) : limitReached ? (
          <>
            <Lock size={18} />
            Limit Reached
          </>
        ) : (
          <>
            <RotateCw size={18} />
            Generate Another Riddle
          </>
        )}
      </Button>

      {/* ── Typed error state ── */}
      {errorMsg && (
        <div className="flex items-start gap-3 p-4 bg-error-bg border border-error/10 rounded-xl">
          <AlertTriangle className="text-error shrink-0 mt-0.5" size={16} />
          <div className="flex flex-col gap-1">
            <span className="text-xs font-bold text-error uppercase tracking-wider">
              {errorCode === 'GENERATION_TIMEOUT' ? 'Timed Out'
                : errorCode === 'GENERATION_ERROR' ? 'AI Unavailable'
                : errorCode === 'QUOTA_EXCEEDED' ? 'Limit Reached'
                : 'Generation Failed'}
            </span>
            <p className="text-xs text-text-2 leading-relaxed">
              {errorMsg}
            </p>
          </div>
        </div>
      )}

      {/* ── DEV TRACE ── */}
      {process.env.NODE_ENV === 'development' && (
        <div className="p-4 bg-bg-subtle border border-border rounded-xl font-mono text-[10px] text-text-4 leading-relaxed">
          <div className="flex items-center gap-2 mb-2">
            <Badge variant="secondary" size="sm">DEV TRACE</Badge>
          </div>
          <div>Used today: <span className="text-text-2 font-bold">{used} / {MAX_PER_DAY}</span></div>
          {templateFamily && <div>Template: <span className="text-primary">{templateFamily}</span></div>}
          {attempts.length > 0 && (
             <div className="mt-2 pt-2 border-t border-border/50">
               <div className="mb-1 uppercase font-bold">Failed Attempts:</div>
               {attempts.map((att, idx) => (
                 <div key={idx} className="mb-1 text-error/80">• {att.failedAt}: {att.reason}</div>
               ))}
             </div>
          )}
        </div>
      )}

      {/* ── Quota counter ── */}
      <div className="flex items-center justify-center gap-2 text-xs font-medium text-text-3">
        <Info size={12} />
        {limitReached
          ? 'Daily quota exhausted.'
          : `${MAX_PER_DAY - used} riddle generations remaining today`}
      </div>
    </div>
  );
}

function LoadingSpinner({ label }: { label: string }) {
  return (
    <span style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
      <svg style={{ width: 16, height: 16, animation: 'spin 1s linear infinite' }} viewBox="0 0 24 24">
        <circle cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none" opacity="0.25" />
        <path
          fill="currentColor"
          d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
          opacity="0.75"
        />
      </svg>
      {label}
    </span>
  );
}

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Modal } from '@/components/ui/Modal';
import { Input, Textarea } from '@/components/ui/Input';
import { Button } from '@/components/ui/Button';
import { Badge } from '@/components/ui/Badge';
import { AlertTriangle, Send, CheckCircle2 } from 'lucide-react';

interface ChallengeModalProps {
  isOpen: boolean;
  onClose: () => void;
  riddleId: string;
  riddleQuestion: string;
}

export function ChallengeModal({ isOpen, onClose, riddleId, riddleQuestion }: ChallengeModalProps) {
  const [proposedAnswer, setProposedAnswer] = useState('');
  const [reasoning, setReasoning] = useState('');
  const [proofText, setProofText] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [success, setSuccess] = useState(false);
  const [error, setError] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setError('');

    try {
      const res = await fetch('/api/challenges', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          riddleId,
          proposedAnswer,
          reasoning,
          proofText
        }),
      });

      const data = await res.json();
      if (!res.ok) throw new Error(data.error || 'Submission failed');

      setSuccess(true);
      setTimeout(() => {
        onClose();
        setSuccess(false);
        setProposedAnswer('');
        setReasoning('');
        setProofText('');
      }, 3000);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsSubmitting(false);
    }
  };


  return (
    <Modal 
      isOpen={isOpen} 
      onClose={onClose} 
      title="Dispute Answer" 
      className="max-w-lg"
    >
      {success ? (
        <div className="flex flex-col items-center text-center py-12 gap-4">
          <div className="w-16 h-16 rounded-full bg-success/10 flex items-center justify-center text-success mb-2">
            <CheckCircle2 size={40} />
          </div>
          <h3 className="text-xl font-bold text-text-1">Dispute Filed Successfully</h3>
          <p className="text-sm text-text-3 max-w-xs">
            Our mathematical review team will analyze your reasoning. You'll receive a notification and bonus XP if your claim is verified.
          </p>
        </div>
      ) : (
        <form onSubmit={handleSubmit} className="flex flex-col gap-6">
          <div className="flex items-start gap-4 p-4 bg-warning/5 border border-warning/10 rounded-xl mb-2">
            <AlertTriangle className="text-warning shrink-0 mt-0.5" size={18} />
            <div className="flex flex-col gap-1">
              <span className="text-xs font-bold text-warning uppercase tracking-wider">Academic Integrity</span>
              <p className="text-xs text-text-2 leading-relaxed">
                Only file a dispute if you are mathematically certain the official answer is incorrect. Frivolous disputes may impact your reputation rank.
              </p>
            </div>
          </div>

          <div className="flex flex-col gap-1.5">
            <label className="label">Proposed Correct Answer</label>
            <Input
              required
              value={proposedAnswer}
              onChange={(e) => setProposedAnswer(e.target.value)}
              placeholder="What should the answer be?"
            />
          </div>

          <div className="flex flex-col gap-1.5">
            <label className="label">Mathematical Reasoning</label>
            <Textarea
              required
              minLength={10}
              value={reasoning}
              onChange={(e) => setReasoning(e.target.value)}
              placeholder="Explain the error in logic step-by-step..."
              className="min-h-[120px]"
            />
          </div>

          <div className="flex flex-col gap-1.5">
            <label className="label">Reference / Proof (Optional)</label>
            <Input
              value={proofText}
              onChange={(e) => setProofText(e.target.value)}
              placeholder="WolframAlpha link, theorem name, etc."
            />
          </div>

          {error && (
            <p className="text-xs font-bold text-error bg-error/5 p-3 rounded-lg border border-error/10">
              {error}
            </p>
          )}

          <div className="flex gap-3 pt-4 border-t border-border mt-2">
            <Button 
              type="button" 
              variant="secondary" 
              onClick={onClose} 
              className="flex-1"
              disabled={isSubmitting}
            >
              Cancel
            </Button>
            <Button 
              type="submit" 
              className="flex-1 gap-2"
              disabled={isSubmitting}
            >
              {isSubmitting ? 'Processing...' : (
                <>
                  <Send size={16} />
                  File Dispute
                </>
              )}
            </Button>
          </div>
        </form>
      )}
    </Modal>
  );
}

import React, { useEffect, useState } from 'react';

interface ImagePreviewProps {
  date: string;
  difficulty: string;
  streak?: number;
  isSolved?: boolean;
  onLoaded?: (dataUrl: string) => void;
}

export default function ImagePreview({ date, difficulty, streak = 0, isSolved = false, onLoaded }: ImagePreviewProps) {
  const [dataUrl, setDataUrl] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let active = true;
    const fetchImage = async () => {
      setLoading(true);
      try {
        const res = await fetch(`/api/share/image?date=${date}&difficulty=${difficulty}&streak=${streak}&isSolved=${isSolved}`);
        const data = await res.json();
        if (active && data.image_data_url) {
          setDataUrl(data.image_data_url);
          onLoaded?.(data.image_data_url);
        }
      } catch (err) {
        console.error('Failed to load image preview:', err);
      } finally {
        if (active) setLoading(false);
      }
    };
    fetchImage();
    return () => { active = false; };
  }, [date, difficulty, streak, isSolved, onLoaded]);

  return (
    <div className="w-full aspect-square rounded-xl border border-border bg-bg-muted overflow-hidden flex items-center justify-center">
      {loading ? (
        <div className="flex flex-col items-center gap-3">
          <div className="w-5 h-5 border-2 border-text-4 border-t-text-2 rounded-full animate-spin" />
          <span className="text-xs text-text-3">Generating…</span>
        </div>
      ) : dataUrl ? (
        <img src={dataUrl} alt="Challenge preview" className="w-full h-full object-cover" />
      ) : (
        <span className="text-sm text-text-3">Preview unavailable</span>
      )}
    </div>
  );
}

'use client';
import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Riddle } from '@/types';
import ImagePreview from './ImagePreview';
import CaptionEditor from './CaptionEditor';
import {
  PLATFORM_LIMITS,
  generateLinkedInCaption,
  generateWhatsAppCaption
} from '@/lib/share/generateCaption';
import {
  getLinkedInShareUrl,
  getWhatsAppShareUrl
} from '@/lib/share/getShareUrl';
import { useChallengeSession } from '@/components/providers/ChallengeSessionProvider';

const BASE_URL = process.env.NEXT_PUBLIC_APP_URL || "https://daily-maths-riddle.vercel.app";

interface ShareModalProps {
  riddle: Partial<Riddle>;
  date: string;
  onClose: () => void;
}

type Platform = 'linkedin' | 'whatsapp' | 'instagram';

export default function ShareModal({ riddle, date, onClose }: ShareModalProps) {
  const { session } = useChallengeSession();
  const [platform, setPlatform] = useState<Platform>('linkedin');
  const [captions, setCaptions] = useState<Record<Platform, string>>({
    linkedin: '',
    whatsapp: '',
    instagram: '',
  });
  const [imageDataUrl, setImageDataUrl] = useState<string | null>(null);
  const [toast, setToast] = useState<string | null>(null);

  const shareUrl = `${BASE_URL}/riddle/${date}?difficulty=${riddle.difficulty ?? 'medium'}`;

  useEffect(() => {
    if (shareUrl) {
      const input = { riddle, date, url: shareUrl };
      const li = generateLinkedInCaption(input);
      setCaptions({
        linkedin: li,
        whatsapp: generateWhatsAppCaption(input),
        instagram: li, // reuse linkedin for instagram
      });
    }
  }, [riddle, date, shareUrl]);

  useEffect(() => {
    const handler = (e: KeyboardEvent) => { if (e.key === 'Escape') onClose(); };
    document.addEventListener('keydown', handler);
    return () => document.removeEventListener('keydown', handler);
  }, [onClose]);

  const handleToast = (msg: string) => {
    setToast(msg);
    setTimeout(() => setToast(null), 3000);
  };

  const handleShare = async (p: Platform) => {
    const text = captions[p];

    if (p === 'instagram') {
      // Instagram flow: Download image + Copy caption
      if (imageDataUrl) {
        try {
          const a = document.createElement('a');
          a.href = imageDataUrl;
          a.download = `advaitai-riddle-${date}.svg`;
          document.body.appendChild(a);
          a.click();
          document.body.removeChild(a);

          await navigator.clipboard.writeText(text);
          handleToast('Image downloaded + caption copied. Post on Instagram.');
        } catch (e) {
          handleToast('Failed to download image or copy caption.');
        }
      } else {
        handleToast('Please wait for image to generate.');
      }
      return;
    }

    if (p === 'linkedin') {
      try {
        await navigator.clipboard.writeText(text);
        handleToast('Caption copied. Paste it on LinkedIn.');
      } catch (e) {
        handleToast('Failed to copy caption. Proceeding anyway.');
      }
      const url = getLinkedInShareUrl(shareUrl);
      setTimeout(() => {
        window.open(url, '_blank', 'noopener,noreferrer');
      }, 800);
      return;
    }

    if (p === 'whatsapp') {
      const url = getWhatsAppShareUrl(text, shareUrl);
      window.open(url, '_blank', 'noopener,noreferrer');
      return;
    }
  };

  const currentMaxChars = PLATFORM_LIMITS[platform === 'instagram' ? 'linkedin' : platform];

  return (
    <div className="modal-backdrop" onClick={onClose} style={{ zIndex: 100 }}>
      <motion.div
        initial={{ opacity: 0, scale: 0.96, y: 12 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        exit={{ opacity: 0, scale: 0.97, y: 6 }}
        transition={{ duration: 0.42, ease: [0.16, 1, 0.3, 1] }}
        className="modal-card relative w-full max-w-4xl overflow-hidden rounded-2xl border border-white/[0.12] bg-gradient-to-br from-zinc-950 via-zinc-950 to-zinc-900 shadow-[0_0_0_1px_rgba(255,255,255,0.04),0_40px_120px_rgba(0,0,0,0.75)] flex flex-col md:flex-row"
        onClick={e => e.stopPropagation()}
        style={{ maxWidth: 900, minHeight: 500 }}
      >
        {/* Toast */}
        <AnimatePresence>
          {toast && (
            <motion.div
              initial={{ opacity: 0, y: -20, x: '-50%' }}
              animate={{ opacity: 1, y: 0, x: '-50%' }}
              exit={{ opacity: 0, y: -20, x: '-50%' }}
              className="absolute top-4 left-1/2 bg-zinc-800 text-zinc-100 px-5 py-2.5 rounded-full text-sm font-medium z-50 border border-zinc-700 shadow-xl"
            >
              {toast}
            </motion.div>
          )}
        </AnimatePresence>

        {/* Close Button */}
        <button
          onClick={onClose}
          className="absolute top-5 right-5 z-10 text-zinc-500 hover:text-white transition-colors bg-zinc-900/80 hover:bg-zinc-800 rounded-full p-2 border border-zinc-800 hover:border-zinc-700"
          aria-label="Close"
        >
          <svg width="18" height="18" viewBox="0 0 24 24" fill="none">
            <path d="M18 6L6 18M6 6l12 12" stroke="currentColor" strokeWidth="2" strokeLinecap="round"/>
          </svg>
        </button>

        {/* LEFT: Riddle Context */}
        <div className="w-full md:w-[45%] p-8 md:p-10 border-b md:border-b-0 md:border-r border-zinc-800/60 bg-zinc-900/30 flex flex-col">
          <h2 className="mb-8 font-display text-3xl font-normal tracking-tight text-zinc-100 md:text-[2rem]">Share result</h2>

          <div className="flex-1 flex flex-col">
            <span className="text-[11px] font-semibold tracking-widest text-zinc-500 uppercase mb-3 block">
              Challenge preview
            </span>
            <div className="bg-zinc-900/60 border border-zinc-800/80 rounded-2xl p-6 flex flex-col gap-4 shadow-inner">
              <div className="flex flex-wrap items-center gap-2">
                <span className="text-[10px] font-bold uppercase tracking-wider px-2.5 py-1 bg-zinc-800/80 rounded-md text-zinc-300 border border-zinc-700/50">
                  {riddle.category}
                </span>
                <span className="text-[10px] font-bold uppercase tracking-wider px-2.5 py-1 bg-zinc-800/80 rounded-md text-zinc-400 border border-zinc-700/50">
                  {riddle.difficulty}
                </span>
              </div>
              <p className="text-zinc-200 text-[15px] leading-relaxed font-medium">
                {riddle.question}
              </p>
            </div>
          </div>
        </div>

        {/* RIGHT: Platform Settings & Action */}
        <div className="flex-1 p-8 md:p-10 bg-zinc-950 flex flex-col relative">

          {/* Platform Tabs */}
          <div className="flex gap-1 p-1.5 bg-zinc-900/80 rounded-xl mb-8 border border-zinc-800/80 w-full max-w-sm mr-auto">
            {(['linkedin', 'whatsapp', 'instagram'] as Platform[]).map(p => (
              <button
                key={p}
                onClick={() => setPlatform(p)}
                className={`flex-1 py-2 text-xs font-semibold tracking-wide rounded-lg capitalize transition-all duration-200 ${
                  platform === p 
                    ? 'bg-zinc-800 text-white shadow-sm border border-zinc-700' 
                    : 'text-zinc-400 hover:text-zinc-200 border border-transparent'
                }`}
              >
                {p}
              </button>
            ))}
          </div>

          {/* Content Layout */}
          <div className="flex flex-col sm:flex-row gap-6 mb-8 flex-1">
            {/* Asset Preview */}
            <div className="w-full sm:w-[140px] flex-shrink-0">
              <span className="text-[11px] font-semibold tracking-widest text-zinc-500 uppercase mb-3 block">
                Image
              </span>
              <div className="rounded-xl overflow-hidden shadow-2xl border border-zinc-800 bg-zinc-900 aspect-square">
                <ImagePreview 
                  date={date} 
                  difficulty={riddle.difficulty ?? 'medium'} 
                  streak={session?.streak.currentStreak || 0}
                  isSolved={session?.solvedToday || false}
                  onLoaded={setImageDataUrl} 
                />
              </div>
            </div>

            {/* Caption Editor */}
            <div className="flex-1 flex flex-col">
              <CaptionEditor
                value={captions[platform]}
                onChange={(val) => setCaptions({ ...captions, [platform]: val })}
                platform={platform}
                maxChars={currentMaxChars}
              />
            </div>
          </div>

          {/* Action Button */}
          <button
            onClick={() => handleShare(platform)}
            className="w-full mt-auto py-4 bg-zinc-100 text-zinc-950 rounded-xl font-bold text-[15px] tracking-wide hover:bg-white hover:scale-[1.01] active:scale-[0.99] transition-all shadow-[0_0_20px_rgba(255,255,255,0.05)]"
