import { createServiceClient } from '@/utils/supabase/server';

/**
 * Records an immutable audit log entry for an admin action.
 * Non-throwing — audit failures must never break the primary action.
 */
export async function logAdminAction(opts: {
  actorId: string;
  action:
    | 'publish'
    | 'replace'
    | 'rollback'
    | 'regenerate'
    | 'approve'
    | 'reject'
    | 'config_change'
    | 'manual_publish';
  targetType: 'riddle' | 'queue_entry' | 'generation_job' | 'config' | 'scheduled_riddle';
  targetId: string;
  metadata?: Record<string, unknown>;
}): Promise<void> {
  try {
    const supabase = (await createServiceClient()) as any;
    const { error } = await supabase.from('admin_audit_logs').insert({
      actor_id: opts.actorId,
      action: opts.action,
      target_type: opts.targetType,
      target_id: opts.targetId,
      metadata: opts.metadata ?? {},
    });

    if (error) {
      console.error('[audit] Failed to write audit log:', error.message);
    }
  } catch (err) {
    console.error('[audit] Unexpected error writing audit log:', err);
  }
}

/**
 * Fetches audit log entries, ordered newest first.
 */
export async function getAuditLogs(opts?: {
  action?: string;
  actorId?: string;
  limit?: number;
  offset?: number;
}): Promise<{ logs: any[]; total: number }> {
  const supabase = (await createServiceClient()) as any;
  const limit = opts?.limit ?? 50;
  const offset = opts?.offset ?? 0;

  let query = supabase
    .from('admin_audit_logs')
    .select('*, actor:profiles!actor_id(username, full_name)', { count: 'exact' })
    .order('created_at', { ascending: false })
    .range(offset, offset + limit - 1);

  if (opts?.action) query = query.eq('action', opts.action);
  if (opts?.actorId) query = query.eq('actor_id', opts.actorId);

  const { data, count, error } = await query;

  if (error) {
    console.error('[audit] Failed to fetch audit logs:', error.message);
    return { logs: [], total: 0 };
  }

  return { logs: data ?? [], total: count ?? 0 };
}

import { createServiceClient } from '@/utils/supabase/server';
import type { PipelineEventType, PipelineStats } from '@/types/analytics';

export interface AdminCounts {
  profiles: number;
  publishedRiddles: number;
  solvedAttempts: number;
}

export interface AdminOverview {
  counts: AdminCounts;
  pipeline: PipelineStats | null;
  pipelineError: string | null;
}

/**
 * Aggregated admin metrics from Supabase (service role).
 * Used by the admin dashboard and /api/admin/stats.
 */
export async function getAdminOverview(days: number): Promise<AdminOverview> {
  const supabase = (await createServiceClient()) as any;

  const [profilesRes, riddlesRes, attemptsRes] = await Promise.all([
    supabase.from('profiles').select('*', { head: true, count: 'exact' }),
    supabase.from('riddles').select('*', { head: true, count: 'exact' }).eq('status', 'published'),
    supabase.from('user_attempts').select('*', { head: true, count: 'exact' }).eq('status', 'solved'),
  ]);

  const counts: AdminCounts = {
    profiles: profilesRes.count ?? 0,
    publishedRiddles: riddlesRes.count ?? 0,
    solvedAttempts: attemptsRes.count ?? 0,
  };

  const from = new Date(Date.now() - days * 86_400_000).toISOString();
  const to = new Date().toISOString();

  const { data: events, error } = await supabase
    .from('pipeline_events')
    .select('*')
    .gte('created_at', from)
    .order('created_at', { ascending: false })
    .limit(500);

  if (error) {
    return { counts, pipeline: null, pipelineError: error.message };
  }

  const rows = (events ?? []) as Array<{
    event_type: PipelineEventType;
    difficulty: string;
    is_daily: boolean;
    duration_ms: number | null;
    validation_score: number | null;
    candidates_tried: number;
    failure_reason: string | null;
    created_at: string;
  }>;

  const total = rows.length;
  const successes = rows.filter((r) => r.event_type === 'success').length;

  const byType = rows.reduce((acc, r) => {
    acc[r.event_type] = (acc[r.event_type] ?? 0) + 1;
    return acc;
  }, {} as Record<PipelineEventType, number>);

  const byDiff = rows.reduce(
    (acc, r) => {
      if (!acc[r.difficulty]) acc[r.difficulty] = { runs: 0, successes: 0, successPct: 0 };
      acc[r.difficulty].runs++;
      if (r.event_type === 'success') acc[r.difficulty].successes++;
      return acc;
    },
    {} as Record<string, { runs: number; successes: number; successPct: number }>,
  );
  Object.values(byDiff).forEach((d) => {
    d.successPct = d.runs > 0 ? Math.round((d.successes / d.runs) * 100) : 0;
  });

  const successRows = rows.filter((r) => r.event_type === 'success');
  const avgMs =
    successRows.length > 0
      ? Math.round(successRows.reduce((s, r) => s + (r.duration_ms ?? 0), 0) / successRows.length)
      : null;
  const avgScore =
    successRows.length > 0
      ? Number((successRows.reduce((s, r) => s + (r.validation_score ?? 0), 0) / successRows.length).toFixed(2))
      : null;
  const avgCandidates =
    total > 0 ? Number((rows.reduce((s, r) => s + r.candidates_tried, 0) / total).toFixed(1)) : null;

  const pipeline: PipelineStats = {
    period: { from, to, days },
    totals: { runs: total, successes, failures: total - successes },
    rates: {
      successPct: total > 0 ? Math.round((successes / total) * 100) : 0,
      duplicateRatePct: total > 0 ? Math.round(((byType.duplicate_rejected ?? 0) / total) * 100) : 0,
      validationFailPct: total > 0 ? Math.round(((byType.validation_failed ?? 0) / total) * 100) : 0,
      rateLimitedPct: total > 0 ? Math.round(((byType.rate_limited ?? 0) / total) * 100) : 0,
    },
    performance: { avgSuccessMs: avgMs, avgValidationScore: avgScore, avgCandidatesTried: avgCandidates },
    breakdown: byType,
    byDifficulty: byDiff,
    recentEvents: rows.slice(0, 20).map((r) => ({
      eventType: r.event_type,
      difficulty: r.difficulty,
      isDaily: r.is_daily,
      durationMs: r.duration_ms,
      validationScore: r.validation_score,
      failureReason: r.failure_reason,
      createdAt: r.created_at,
    })),
  };

  return { counts, pipeline, pipelineError: null };
}

import { createServiceClient } from '@/utils/supabase/server';
import { runGenerationPipeline } from '@/lib/generation/pipeline';
import { logAdminAction } from '@/lib/admin/auditLog';

// ── Types ────────────────────────────────────────────────────────

export interface QueueEntry {
  id: string;
  target_date: string;
  difficulty: string;
  riddle_id: string;
  position: number;
  status: 'pending' | 'published' | 'rejected' | 'expired';
  rejected_reason: string | null;
  generated_at: string;
  published_at: string | null;
  riddle?: {
    id: string;
    question: string;
    answer: string;
    explanation: string;
    slug: string;
    category: string;
  };
}

export interface GenerationJob {
  id: string;
  target_date: string;
  difficulty: string;
  status: 'queued' | 'running' | 'completed' | 'failed';
  riddle_id: string | null;
  queue_entry_id: string | null;
  error_message: string | null;
  retry_count: number;
  duration_ms: number | null;
  created_by: string | null;
  started_at: string | null;
  completed_at: string | null;
  created_at: string;
}

// ── Queue Operations ─────────────────────────────────────────────

/**
 * Pre-generates a riddle for a future date and places it in the queue.
 * Returns the generation job record.
 */
export async function preGenerateForDate(
  targetDate: string,
  difficulty: 'easy' | 'medium' | 'hard',
  createdBy?: string | null
): Promise<{ success: boolean; job: GenerationJob | null; error?: string }> {
  const supabase = (await createServiceClient()) as any;
  const startedAt = Date.now();

  // Create job record
  const { data: job, error: jobError } = await supabase
    .from('generation_jobs')
    .insert({
      target_date: targetDate,
      difficulty,
      status: 'running',
      created_by: createdBy ?? null,
      started_at: new Date().toISOString(),
    })
    .select('*')
    .single();

  if (jobError || !job) {
    console.error('[publishPipeline] Failed to create job:', jobError?.message);
    return { success: false, job: null, error: 'Failed to create generation job' };
  }

  try {
    // Run the generation pipeline — produces a real riddle in the DB
    const result = await runGenerationPipeline({
      difficulty,
      isDaily: true,
      dailyDate: targetDate,
    });

    const durationMs = Date.now() - startedAt;

    if (!result.success) {
      // Mark job as failed
      await supabase
        .from('generation_jobs')
        .update({
          status: 'failed',
          error_message: result.error,
          duration_ms: durationMs,
          completed_at: new Date().toISOString(),
        })
        .eq('id', job.id);

      return { success: false, job: { ...job, status: 'failed', error_message: result.error }, error: result.error };
    }

    // Add riddle to queue
    const { data: queueEntry } = await supabase
      .from('daily_riddle_queue')
      .insert({
        target_date: targetDate,
        difficulty,
        riddle_id: result.riddle.id,
        position: 0,
        status: 'pending',
      })
      .select('*')
      .single();

    // Update job as completed
    await supabase
      .from('generation_jobs')
      .update({
        status: 'completed',
        riddle_id: result.riddle.id,
        queue_entry_id: queueEntry?.id ?? null,
        duration_ms: durationMs,
        completed_at: new Date().toISOString(),
      })
      .eq('id', job.id);

    console.log(`[publishPipeline] Generated riddle ${result.riddle.id} for ${targetDate} (${difficulty}) in ${durationMs}ms`);

    return {
      success: true,
      job: { ...job, status: 'completed', riddle_id: result.riddle.id, duration_ms: durationMs },
    };
  } catch (err) {
    const durationMs = Date.now() - startedAt;
    const msg = err instanceof Error ? err.message : String(err);

    await supabase
      .from('generation_jobs')
      .update({
        status: 'failed',
        error_message: msg,
        duration_ms: durationMs,
        completed_at: new Date().toISOString(),
      })
      .eq('id', job.id);

    return { success: false, job: { ...job, status: 'failed', error_message: msg }, error: msg };
  }
}

/**
 * Fetches queue entries for a date, optionally filtered by status.
 */
export async function getQueueForDate(
  date: string,
  status?: 'pending' | 'published' | 'rejected' | 'expired'
): Promise<QueueEntry[]> {
  const supabase = (await createServiceClient()) as any;

  let query = supabase
