    .select('*, riddle:riddles!riddle_id(id, question, answer, explanation, slug, category)')
    .eq('target_date', date)
    .order('position', { ascending: true });

  if (status) query = query.eq('status', status);

  const { data, error } = await query;
  if (error) {
