import { promises as fs } from 'fs';
import path from 'path';
import { AIRiddle, ScoredRiddle } from '@/types/ai';

export interface RiddleStore {
  getByDate(date: string, difficulty: string): Promise<AIRiddle | null>;
  save(date: string, riddle: AIRiddle): Promise<void>;
  getRecent(limit: number): Promise<AIRiddle[]>;
  logRejection(date: string, scoredRiddle: ScoredRiddle, reason: string): Promise<void>;
}

class JsonFileStore implements RiddleStore {
  private getDbPath() {
    return path.join(process.cwd(), 'data', 'generated-riddles.json');
  }

  private getLogPath() {
    return path.join(process.cwd(), 'data', 'rejected-riddles.json');
  }

  private async readDb(): Promise<Record<string, AIRiddle>> {
    try {
      const data = await fs.readFile(this.getDbPath(), 'utf-8');
      return JSON.parse(data);
    } catch {
      return {}; // file doesn't exist yet or is empty
    }
  }

  private async writeDb(data: Record<string, AIRiddle>) {
    await fs.mkdir(path.dirname(this.getDbPath()), { recursive: true });
    await fs.writeFile(this.getDbPath(), JSON.stringify(data, null, 2));
  }

  async getByDate(date: string, difficulty: string): Promise<AIRiddle | null> {
    const db = await this.readDb();
    // We store using a composite key date_difficulty
    const key = `${date}_${difficulty}`;
    return db[key] || null;
  }

  async save(date: string, riddle: AIRiddle): Promise<void> {
    const db = await this.readDb();
    const key = `${date}_${riddle.difficulty}`;
    db[key] = riddle;
    await this.writeDb(db);
  }

  async getRecent(limit: number): Promise<AIRiddle[]> {
    const db = await this.readDb();
    const all = Object.values(db).sort((a, b) => 
      new Date(b.generated_at).getTime() - new Date(a.generated_at).getTime()
    );
    return all.slice(0, limit);
  }

  async logRejection(date: string, scoredRiddle: ScoredRiddle, reason: string): Promise<void> {
    try {
      const logPath = this.getLogPath();
      let logs: any[] = [];
      try {
        const data = await fs.readFile(logPath, 'utf-8');
        logs = JSON.parse(data);
      } catch {}

      logs.push({
        date,
        reason,
        timestamp: new Date().toISOString(),
        scoredRiddle
      });

      await fs.writeFile(logPath, JSON.stringify(logs, null, 2));
    } catch (err) {
      console.error('Failed to log rejection', err);
    }
  }
}

// Export the singleton instance
export const riddleStore: RiddleStore = new JsonFileStore();

import { createServiceClient } from '@/utils/supabase/server';
import type { UserStats } from '@/types/gamification';

/** 
 * Checks for and unlocks new achievements for a user based on their current stats.
 * Returns the names of newly unlocked achievements.
 */
export async function checkAndUnlockAchievements(userId: string, stats: UserStats): Promise<string[]> {
  try {
    const supabase = await createServiceClient();

    // 1. Fetch all possible achievements
    const { data: allAchievements, error: fetchErr } = await supabase
      .from('achievements')
      .select('*') as { data: any[] | null; error: any };

    if (fetchErr || !allAchievements) {
      console.error('[ACHIEVEMENT CHECK] fetch error:', fetchErr?.message);
      return [];
    }

    // 2. Fetch already unlocked achievements for this user
    const { data: unlocked, error: unlockedErr } = await supabase
      .from('user_achievements')
      .select('achievement_id')
      .eq('user_id', userId) as { data: any[] | null; error: any };

    if (unlockedErr) {
      console.error('[ACHIEVEMENT CHECK] unlocked fetch error:', unlockedErr.message);
      return [];
    }

    const unlockedIds = new Set((unlocked || []).map(u => u.achievement_id));
    const newlyUnlocked: string[] = [];

    // 3. Evaluate each achievement
    for (const achievement of allAchievements) {
      if (unlockedIds.has(achievement.id)) continue;

      let met = false;
      switch (achievement.requirement_type) {
        case 'first_solve':
          met = stats.riddles_solved >= achievement.threshold;
          break;
        case 'streak':
          met = stats.current_streak >= achievement.threshold;
          break;
        case 'xp':
          met = stats.total_xp >= achievement.threshold;
          break;
        case 'hard_solve':
          met = stats.hard_solved >= achievement.threshold;
          break;
        case 'accuracy':
          const accuracy = stats.total_attempts > 0 ? (stats.correct_attempts / stats.total_attempts) * 100 : 0;
          met = accuracy >= achievement.threshold && stats.riddles_solved >= 5; // e.g. min 5 solves for accuracy achievement
          break;
      }

      if (met) {
        // Unlock it!
        const { error: unlockErr } = await (supabase
          .from('user_achievements') as any)
          .insert({ user_id: userId, achievement_id: achievement.id });

        if (!unlockErr) {
          newlyUnlocked.push(achievement.name);
          console.log(`[ACHIEVEMENT UNLOCKED] "${achievement.name}" for user ${userId.slice(0, 8)}…`);
        } else {
          console.error(`[ACHIEVEMENT UNLOCK ERROR] "${achievement.name}":`, unlockErr.message);
        }
      }
    }

    return newlyUnlocked;
  } catch (err) {
    console.error('[checkAndUnlockAchievements] unexpected error:', err);
    return [];
  }
}

/**
 * processSolve — the central gamification orchestrator.
 *
 * Called after a correct answer is confirmed server-side.
 * Handles: streak processing, XP calculation, user_stats upsert.
 *
 * Non-throwing — all errors are logged and a partial result is returned.
 */

import type { Difficulty } from '@/types';
import type { SolveResult } from '@/types/gamification';
import { getOfficialDailyDate } from '@/lib/timezone';
import { processStreak } from './streak';
import { calculateXP } from './xp';

export interface ProcessSolveOpts {
  userId: string;
  difficulty: Difficulty;
  riddleId: string | null;
  /** ISO timestamp of when the user first saw the riddle. */
  solveStartedAt: string | null;
  /** Total number of answer submissions (including this final correct one). */
  attemptCount: number;
  hintsUsed: number;
  /** Official calendar date (NEXT_PUBLIC_DAILY_TIMEZONE, default IST). */
  solvedDate?: string;
}

export async function processSolve(opts: ProcessSolveOpts): Promise<SolveResult> {
  const { userId, difficulty, riddleId, solveStartedAt, attemptCount, hintsUsed } = opts;
  const solvedDate = opts.solvedDate ?? getOfficialDailyDate();

  // Calculate solve duration
  let solveTimeSeconds: number | null = null;
  if (solveStartedAt) {
    const elapsed = (Date.now() - new Date(solveStartedAt).getTime()) / 1000;
    solveTimeSeconds = Math.round(elapsed);
    console.log(`[SOLVE DURATION] ${solveTimeSeconds}s`);
  }

  // 1. Process streak
  const { newStreak, bestStreak, wasReset, isMilestone } = await processStreak(userId, solvedDate);

  // 2. Calculate XP
  const { base, bonuses, total: xpTotal } = calculateXP({
    difficulty,
    attemptCount,
    solveTimeSeconds,
    newStreak,
  });

  // 3. Insert XP events
  try {
    const { createServiceClient } = await import('@/utils/supabase/server');
    const supabase = (await createServiceClient()) as any;

    const xpEvents = [
      { user_id: userId, amount: base, reason: `solve_${difficulty}`, riddle_id: riddleId },
      ...bonuses.map(b => ({ user_id: userId, amount: b.amount, reason: b.reason, riddle_id: riddleId })),
    ];
    const { error: xpErr } = await supabase.from('xp_events').insert(xpEvents);
    if (xpErr) console.error('[XP AWARDED] insert error:', xpErr.message);
    else console.log(`[XP AWARDED] +${xpTotal} XP for user ${userId.slice(0, 8)}…`);

    // 4. Upsert user_stats — one atomic operation
    const diffColumn = `${difficulty}_solved` as const;
    const { data: existing } = await supabase
      .from('user_stats')
      .select('total_xp, riddles_solved, easy_solved, medium_solved, hard_solved, total_attempts, correct_attempts')
      .eq('user_id', userId)
      .single();

    const prev = existing ?? {
      total_xp: 0, riddles_solved: 0,
      easy_solved: 0, medium_solved: 0, hard_solved: 0,
      total_attempts: 0, correct_attempts: 0,
    };

    const statsUpdate = {
      user_id: userId,
      total_xp: (prev.total_xp ?? 0) + xpTotal,
      current_streak: newStreak,
      best_streak: bestStreak,
      riddles_solved: (prev.riddles_solved ?? 0) + 1,
      easy_solved:   (prev.easy_solved ?? 0)   + (difficulty === 'easy'   ? 1 : 0),
      medium_solved: (prev.medium_solved ?? 0) + (difficulty === 'medium' ? 1 : 0),
      hard_solved:   (prev.hard_solved ?? 0)   + (difficulty === 'hard'   ? 1 : 0),
      total_attempts:   (prev.total_attempts ?? 0)   + attemptCount,
      correct_attempts: (prev.correct_attempts ?? 0) + 1,
      last_solved_date: solvedDate,
    };

    const { error: statsErr } = await supabase
      .from('user_stats')
      .upsert(statsUpdate, { onConflict: 'user_id' });

    if (statsErr) console.error('[STATS RECALCULATION] upsert error:', statsErr.message);
    else console.log('[STATS RECALCULATION] user_stats updated for', userId.slice(0, 8) + '…');

    // 5. Check for achievement unlocks
    const { checkAndUnlockAchievements } = await import('./achievements');
    const newlyUnlocked = await checkAndUnlockAchievements(userId, statsUpdate as any);

    return {
      xpAwarded: xpTotal,
      newStreak,
      wasStreakReset: wasReset,
      isStreakMilestone: isMilestone,
      bonuses,
      newlyUnlockedAchievements: newlyUnlocked,
    };

  } catch (err) {
    console.error('[processSolve] unexpected error:', err);
  }

  return {
    xpAwarded: xpTotal,
    newStreak,
    wasStreakReset: wasReset,
    isStreakMilestone: isMilestone,
    bonuses,
  };
}

/**
 * Server-side streak engine.
 * All calendar dates use the official daily timezone (see lib/timezone.ts).
 * Never reads from localStorage.
 */

import { getOfficialDailyDate, getYesterdayOfficial } from '@/lib/timezone';

export interface StreakProcessResult {
  newStreak: number;
  bestStreak: number;
  wasReset: boolean;
  isMilestone: boolean;
}

const STREAK_MILESTONES = [3, 7, 14, 30, 60, 100];

/**
 * Processes a solve event for the given user and date.
 * Reads and writes user_stats + streak_events tables.
 *
 * Returns the new streak value (or 0 if it couldn't be determined).
 */
export async function processStreak(
  userId: string,
  solvedDate: string = getOfficialDailyDate()
): Promise<StreakProcessResult> {
  const { createServiceClient } = await import('@/utils/supabase/server');
  const supabase = (await createServiceClient()) as any;

  // Fetch current stats
  const { data: stats } = await supabase
    .from('user_stats')
    .select('current_streak, best_streak, last_solved_date')
    .eq('user_id', userId)
    .single();

  const lastSolved: string | null = stats?.last_solved_date ?? null;
  const currentStreak: number = stats?.current_streak ?? 0;
  const bestStreak: number = stats?.best_streak ?? 0;

  let newStreak: number;
  let eventType: 'increment' | 'reset';
  let wasReset = false;

  if (lastSolved === solvedDate) {
    // Already recorded today — no-op, return current state
    console.log('[STREAK] already recorded for', solvedDate);
    return {
      newStreak: currentStreak,
      bestStreak,
      wasReset: false,
      isMilestone: false,
    };
  }

  if (lastSolved === getYesterdayOfficial() || (lastSolved === null && currentStreak === 0)) {
    // Consecutive day (or first solve ever)
    newStreak = currentStreak + 1;
    eventType = 'increment';
    console.log(`[STREAK INCREMENT] ${currentStreak} → ${newStreak}`);
  } else {
    // Gap detected — streak broken
    newStreak = 1;
    eventType = 'reset';
    wasReset = true;
    console.log(`[STREAK RESET] was ${currentStreak}, restarting at 1`);
  }

  const newBest = Math.max(bestStreak, newStreak);
  const isMilestone = STREAK_MILESTONES.includes(newStreak);

  // Insert streak event
  await supabase.from('streak_events').insert({
    user_id: userId,
    event_type: eventType,
    streak_value: newStreak,
    solved_date: solvedDate,
  });

  return { newStreak, bestStreak: newBest, wasReset, isMilestone };
}

import type { Difficulty } from '@/types';
import type { XPBonus } from '@/types/gamification';

/** Base XP per difficulty. */
export const XP_TABLE: Record<Difficulty, number> = {
  easy:   10,
  medium: 25,
  hard:   50,
};

/** Bonus XP amounts. */
export const BONUS_FIRST_TRY  = 15;
export const BONUS_FAST_SOLVE = 10; // awarded if solve time < 60s
export const FAST_SOLVE_THRESHOLD_S = 60;

/** Streak values at which a milestone bonus fires. */
export const STREAK_MILESTONES = [3, 7, 14, 30, 60, 100];
export const MILESTONE_BONUS = 25;

/** XP awarded when a user gives up (reduced award). */
export const XP_GIVE_UP = 5;

/**
 * Calculates the full XP breakdown for a solve event.
 * Pure — does not touch the DB.
 */
export function calculateXP(opts: {
  difficulty: Difficulty;
  attemptCount: number;
  solveTimeSeconds: number | null;
  newStreak: number;
}): { base: number; bonuses: XPBonus[]; total: number } {
  const base = XP_TABLE[opts.difficulty];
  const bonuses: XPBonus[] = [];

  if (opts.attemptCount === 1) {
    bonuses.push({ reason: 'first_try_bonus', amount: BONUS_FIRST_TRY });
  }

  if (opts.solveTimeSeconds !== null && opts.solveTimeSeconds < FAST_SOLVE_THRESHOLD_S) {
    bonuses.push({ reason: 'fast_solve_bonus', amount: BONUS_FAST_SOLVE });
  }

  if (STREAK_MILESTONES.includes(opts.newStreak)) {
    bonuses.push({
      reason: `streak_milestone_${opts.newStreak}`,
      amount: MILESTONE_BONUS,
    });
  }

  const total = base + bonuses.reduce((s, b) => s + b.amount, 0);
  return { base, bonuses, total };
}

/**
 * Persists XP events and increments user_stats.total_xp.
 * Uses service client to bypass RLS.
 * Non-throwing — XP failures should not block the solve response.
 */
export async function awardXP(opts: {
  userId: string;
  base: number;
  bonuses: XPBonus[];
  riddleId: string | null;
}): Promise<void> {
  const { createServiceClient } = await import('@/utils/supabase/server');
  const supabase = (await createServiceClient()) as any;

  // 1. Anti-abuse: Check if base XP already awarded for this riddle
  if (opts.riddleId) {
    const { data: existing } = await supabase
      .from('xp_events')
      .select('id')
      .eq('user_id', opts.userId)
      .eq('riddle_id', opts.riddleId)
      .eq('reason', 'solve_base')
      .maybeSingle();

    if (existing) {
      console.warn(`[XP ABUSE PREVENTED] User ${opts.userId} already received XP for riddle ${opts.riddleId}`);
      return;
    }
  }

  const events = [
    { user_id: opts.userId, amount: opts.base, reason: 'solve_base', riddle_id: opts.riddleId },
    ...opts.bonuses.map(b => ({
      user_id: opts.userId,
      amount: b.amount,
      reason: b.reason,
      riddle_id: opts.riddleId,
    })),
  ];

  const totalXP = opts.base + opts.bonuses.reduce((s, b) => s + b.amount, 0);

  // Insert all XP events
  const { error: evtErr } = await supabase.from('xp_events').insert(events);
  if (evtErr) console.error('[XP AWARDED] insert error:', evtErr.message);
  else console.log(`[XP AWARDED] +${totalXP} XP (base ${opts.base} + ${opts.bonuses.length} bonuses)`);

  // Increment total_xp in user_stats (upsert handled by processSolve)
  // XP stat increment handled atomically by processSolve's user_stats upsert
}

/**
 * Recalculates a user's total XP from the immutable xp_events log.
 * Useful for auditing or restoring state after invalidations.
 */
export async function recalculateTotalXP(userId: string): Promise<number> {
  try {
    const { createServiceClient } = await import('@/utils/supabase/server');
    const supabase = (await createServiceClient()) as any;

    const { data: events } = await supabase
      .from('xp_events')
      .select('amount')
      .eq('user_id', userId);

    const newTotal = (events || []).reduce((acc: number, e: any) => acc + e.amount, 0);

    await supabase
      .from('user_stats')
      .update({ total_xp: newTotal })
      .eq('user_id', userId);

    console.log(`[XP RECALCULATED] User ${userId}: ${newTotal} XP`);
    return newTotal;
  } catch (err) {
    console.error('[XP RECALCULATED ERROR]', err);
    return 0;
  }
}

import { createClient } from '@/utils/supabase/server';
import type { DbRiddle, DbRiddleInsert } from '@/types/supabase';

/**
 * All Supabase query operations for the riddles table.
 * Uses service client for writes (bypasses RLS) and anon client for reads.
 */

// ── READ ─────────────────────────────────────────────────────────

/**
 * Fetch a published riddle by its slug.
 * Returns null if not found or not published.
 */
export async function getRiddleBySlug(slug: string): Promise<DbRiddle | null> {
  const supabase = await createClient();
  const { data, error } = await supabase
    .from('riddles')
    .select('*')
    .eq('slug', slug)
    .eq('status', 'published')
    .single();

  if (error || !data) return null;
  return data as DbRiddle;
}

/**
 * Fetch the daily riddle for a given date and difficulty.
 * Returns null if not yet generated for this date.
 */
export async function getDailyRiddle(
  date: string,
  difficulty: string
): Promise<DbRiddle | null> {
  const supabase = await createClient();
  const { data, error } = await supabase
    .from('riddles')
    .select('*')
    .eq('daily_date', date)
    .eq('difficulty', difficulty)
    .eq('is_daily', true)
    .eq('status', 'published')
    .single();

  if (error || !data) return null;
  return data as DbRiddle;
}

/**
 * Fetch a scheduled riddle for a specific date and difficulty.
 */
export async function getScheduledRiddle(
  date: string,
  difficulty: string
): Promise<any | null> {
  const supabase = await createClient();
  const { data, error } = await supabase
    .from('scheduled_riddles')
    .select('*')
    .eq('publish_date', date)
    .eq('difficulty', difficulty)
    .in('status', ['scheduled', 'published'])
    .maybeSingle();

  if (error || !data) return null;
  return data;
}

/**
 * Fetch the N most recently published riddles.
 * Used by deduplication logic — only question text is needed.
 */
export async function getRecentRiddleQuestions(limit = 50): Promise<string[]> {
  const supabase = await createClient();
  const { data, error } = await supabase
    .from('riddles')
    .select('question')
    .eq('status', 'published')
    .order('created_at', { ascending: false })
    .limit(limit)
    .returns<Array<{ question: string }>>();

  if (error || !data) return [];
  return data.map((r) => r.question);
}

/**
 * Fetch the N most recently used template families.
 * Used by generation pipeline to enforce cooldowns.
 */
export async function getRecentTemplateFamilies(limit = 20): Promise<string[]> {
  const supabase = await createClient();
  const { data, error } = await supabase
    .from('riddles')
    .select('template_family')
    .eq('status', 'published')
    .not('template_family', 'is', null)
    .order('created_at', { ascending: false })
    .limit(limit)
    .returns<Array<{ template_family: string }>>();

  if (error || !data) return [];
  return (data as Array<{ template_family: string }>).map((r) => r.template_family);
}

/**
 * Fetch a riddle by ID — includes answer, for server-side validation only.
 * Uses anon client since RLS allows reading published riddles.
 */
export async function getRiddleById(id: string): Promise<DbRiddle | null> {
  const supabase = await createClient();
  const { data, error } = await supabase
    .from('riddles')
    .select('*')
    .eq('id', id)
    .eq('status', 'published')
    .single();

  if (error || !data) return null;
  return data as DbRiddle;
}

// ── WRITE (service-role only) ─────────────────────────────────────

/**
 * Inserts a new riddle row.
 * Uses service client to bypass RLS.
 * Returns the inserted row.
 */
export async function insertRiddle(payload: DbRiddleInsert): Promise<DbRiddle | null> {
  const { createServiceClient } = await import('@/utils/supabase/server');
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const supabase = (await createServiceClient()) as any;

  const { data, error } = await supabase
    .from('riddles')
    .insert(payload)
    .select('*')
    .single();

  if (error) {
    console.error('[riddles/queries] insertRiddle error:', error.message);
    return null;
  }
  return data as DbRiddle;
}

/**
 * Inserts a generation log entry after a successful riddle save.
 * Non-throwing — log failures don't break the generation flow.
 */
export async function insertGenerationLog(opts: {
  userId: string | null;
  sessionId: string | null;
  riddleId: string;
  difficulty: string;
  durationMs?: number;
  retryCount?: number;
  templateFamily?: string | null;
}): Promise<void> {
  try {
    const { createServiceClient } = await import('@/utils/supabase/server');
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const supabase = (await createServiceClient()) as any;

    // 1. Legacy rate limiting log
    await supabase.from('generation_logs').insert({
      user_id: opts.userId,
      session_id: opts.sessionId,
      generated_riddle_id: opts.riddleId,
      difficulty: opts.difficulty,
    });

    // 2. New observability log
    await insertPipelineLog({
      userId: opts.userId,
      sessionId: opts.sessionId,
      difficulty: opts.difficulty,
      status: 'success',
      durationMs: opts.durationMs,
      retryCount: opts.retryCount,
      templateFamily: opts.templateFamily
    });

  } catch (err) {
    console.error('[riddles/queries] insertGenerationLog failed:', err);
  }
}

/**
 * Counts how many extra riddles a session generated today.
 * Used for rate limiting.
 */
export async function countTodayGenerations(
  sessionId: string,
  userId: string | null
): Promise<number> {
  const supabase = await createClient();
  const today = new Date().toISOString().slice(0, 10);

  let query = supabase
    .from('generation_logs')
    .select('id', { count: 'exact', head: true })
    .gte('created_at', `${today}T00:00:00Z`);

  if (userId) {
    query = query.eq('user_id', userId);
  } else {
    query = query.eq('session_id', sessionId);
  }

  const { count } = await query;
  return count ?? 0;
}

/**
 * True if this user already has a successful solve recorded for the riddle.
 * Used server-side to prevent duplicate XP / stats increments.
 */
export async function hasUserSolvedRiddle(userId: string, riddleId: string): Promise<boolean> {
  try {
    const { createServiceClient } = await import('@/utils/supabase/server');
    const supabase = (await createServiceClient()) as any;
    const { data } = await supabase
      .from('user_attempts')
      .select('id')
      .eq('user_id', userId)
      .eq('riddle_id', riddleId)
      .eq('status', 'solved')
      .limit(1)
      .maybeSingle();
    return !!data;
  } catch {
    return false;
  }
}

