  icon: string;
  requirement_type: string;
  threshold: number;
}

/** Represents an achievement unlocked by a user */
export interface UserAchievement {
  user_id: string;
  achievement_id: string;
  unlocked_at: string;
  achievement?: Achievement; // for joined queries
}
